#!/usr/bin/env node
/**
 * code_boss — production single-file bundle. Generated by scripts/build.mjs.
 * Starts a local web UI on http://127.0.0.1:<PORT>/ and opens it in the
 * default browser. Talks to an OpenAI-compatible endpoint (api.genai.mil by
 * default). No npm deps. Node 20+ for built-in fetch.
 *
 * Usage:
 *   node code-boss.mjs            (opens the chat UI)
 *   PORT=18999 node code-boss.mjs (override the port)
 *
 * Edit the CONFIG constants below for your environment.
 */

// Build stamp — injected at build time so the running server can report it
// (visible in the Snapshot view). Lets you confirm "yes, this is the bundle
// I just copied over" without guessing from file size.
const BUILD_VERSION = '2026-05-24T02:09:24.888Z';

// ====== CONFIG (edit these) ======
const API_KEY  = '';                                // bearer token
const BASE_URL = 'https://api.genai.mil/v1';        // OpenAI-compatible endpoint
const MODEL    = 'gemini-3.1-pro-preview';          // default model selected in the dropdown
const PORT     = Number(process.env.PORT ?? 18888); // local UI port
// ==================================

import { spawn } from 'node:child_process';
import { createInterface } from 'node:readline';
import { createServer } from 'node:http';
import { homedir } from 'node:os';
import { readFile as _readFile, writeFile as _writeFile, mkdir as _mkdir, stat as _stat, readdir as _readdir } from 'node:fs/promises';
import { existsSync, appendFileSync, mkdirSync } from 'node:fs';
import { randomUUID as _randomUUID } from 'node:crypto';
import path from 'node:path';
const readFile = _readFile, writeFile = _writeFile, mkdir = _mkdir, stat = _stat, readdir = _readdir;
const randomUUID = _randomUUID;


// ====== llm/openai-http.mjs ======
/**
 * Production OpenAI-compatible HTTP adapter — talks to api.genai.mil.
 *
 * Same surface as the dev adapter:
 *   const a = createHttpAdapter({ baseURL, apiKey })
 *   await a.complete(openaiRequest)
 *   for await (const chunk of a.completeStream(openaiRequest)) { ... }
 *
 * Production behaviours wired in here:
 *   - 401 with `unlock_url` → open the URL in the default browser, prompt the
 *     user to press Enter once they've unlocked in the browser, then retry
 *     once. The /user-ui/unlock/... endpoints are browser pages, not API
 *     endpoints — programmatic GET doesn't actually unlock the key.
 *   - 429 with Retry-After header or retry_after_seconds body → sleep, retry
 *     (max 3 attempts, exponential floor)
 *   - SSE streaming parsed into OpenAI ChatCompletionChunk async iterator
 *   - Bearer auth via Authorization header
 *   - Pass-through of unknown fields on assistant messages and tool_calls
 *     (Gemini 3 returns a `thought_signature` field that must round-trip
 *     verbatim to preserve reasoning across function calls). The adapter
 *     never strips fields; the agent loop must echo assistant messages back
 *     intact in subsequent requests.
 *
 * Diagnostics:
 *   - AGENT_DEBUG=1 logs every request's tool_call_ids (outbound) and the
 *     response's assistant.tool_calls[*].id + any non-OpenAI fields seen
 *     (thought_signature, encrypted_content, etc.) so we can verify ID
 *     round-tripping against api.genai.mil on the first real run.
 *
 * No npm deps. Node 18+ built-in fetch only.
 */


const DEFAULT_BASE_URL = 'https://api.genai.mil/v1';

// Standard Chrome install locations on Windows (per-user + per-machine).
const CHROME_PATHS_WIN = [
  (process.env.LOCALAPPDATA || '') + '\\Google\\Chrome\\Application\\chrome.exe',
  'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe',
  'C:\\Program Files (x86)\\Google\\Chrome\\Application\\chrome.exe',
];
function findChromeWin() {
  for (const p of CHROME_PATHS_WIN) {
    try { if (p && existsSync(p)) return p; } catch {}
  }
  return null;
}

function openInBrowser(url) {
  // Prefer Chrome; fall back to the OS default if Chrome isn't installed.
  if (process.platform === 'win32') {
    const chrome = findChromeWin();
    if (chrome) {
      spawn(chrome, [url], { stdio: 'ignore', detached: true }).unref();
    } else {
      spawn('cmd', ['/c', 'start', '""', url], { stdio: 'ignore', detached: true, windowsHide: true }).unref();
    }
  } else if (process.platform === 'darwin') {
    spawn('open', ['-a', 'Google Chrome', url], { stdio: 'ignore', detached: true }).unref();
  } else {
    spawn('google-chrome', [url], { stdio: 'ignore', detached: true })
      .on('error', () => spawn('xdg-open', [url], { stdio: 'ignore', detached: true }).unref())
      .unref();
  }
}

function promptEnter(message) {
  return new Promise((resolve) => {
    const rl = createInterface({ input: process.stdin, output: process.stderr });
    rl.question(message, () => { rl.close(); resolve(); });
  });
}

class HttpError extends Error {
  constructor(status, statusText, body) {
    super(`HTTP ${status} ${statusText}: ${typeof body === 'string' ? body.slice(0, 500) : JSON.stringify(body).slice(0, 500)}`);
    this.status = status;
    this.statusText = statusText;
    this.body = body;
  }
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

// Known OpenAI fields on assistant messages and tool_calls — used to detect
// vendor-specific extras (e.g. Gemini's thought_signature).
const OPENAI_MESSAGE_FIELDS = new Set(['role', 'content', 'tool_calls', 'tool_call_id', 'refusal', 'name', 'function_call']);
const OPENAI_TOOL_CALL_FIELDS = new Set(['id', 'type', 'function', 'index']);
const OPENAI_FUNCTION_FIELDS = new Set(['name', 'arguments']);

function findExtras(obj, knownSet) {
  if (!obj || typeof obj !== 'object') return null;
  const extras = {};
  let any = false;
  for (const k of Object.keys(obj)) {
    if (!knownSet.has(k)) { extras[k] = obj[k]; any = true; }
  }
  return any ? extras : null;
}

function summarizeResponseExtras(json) {
  const out = { messageExtras: null, toolCalls: [] };
  const msg = json?.choices?.[0]?.message;
  if (!msg) return out;
  out.messageExtras = findExtras(msg, OPENAI_MESSAGE_FIELDS);
  for (const tc of msg.tool_calls ?? []) {
    out.toolCalls.push({
      id: tc.id,
      name: tc.function?.name,
      tcExtras: findExtras(tc, OPENAI_TOOL_CALL_FIELDS),
      fnExtras: findExtras(tc.function, OPENAI_FUNCTION_FIELDS),
    });
  }
  return out;
}

function summarizeRequestToolFlow(body) {
  // Pulls out the tool-related shape of what we're SENDING — to verify IDs
  // round-trip.
  const out = { toolDefs: [], assistantToolCallIds: [], toolMessageIds: [] };
  if (Array.isArray(body.tools)) {
    for (const t of body.tools) if (t.function?.name) out.toolDefs.push(t.function.name);
  }
  for (const m of body.messages ?? []) {
    if (m.role === 'assistant' && Array.isArray(m.tool_calls)) {
      for (const tc of m.tool_calls) out.assistantToolCallIds.push(tc.id);
    }
    if (m.role === 'tool' && m.tool_call_id) out.toolMessageIds.push(m.tool_call_id);
  }
  return out;
}

function parseRetryAfter(headers, body) {
  const headerVal = headers.get?.('retry-after');
  const headerSec = headerVal ? Number(headerVal) : NaN;
  const bodySec = Number(body?.retry_after_seconds);
  const candidates = [headerSec, bodySec].filter((n) => Number.isFinite(n) && n > 0);
  if (candidates.length === 0) return 1;
  return Math.max(...candidates);
}

async function readJson(res) {
  const text = await res.text();
  try {
    return JSON.parse(text);
  } catch {
    return { raw: text };
  }
}

/**
 * @param {object} opts
 * @param {string} [opts.baseURL]     Defaults to https://api.genai.mil/v1
 * @param {string} [opts.apiKey]      Bearer token. Defaults to process.env.AGENT_API_KEY.
 * @param {Function} [opts.fetchImpl] Override for tests (default: globalThis.fetch).
 * @param {number}   [opts.maxRetries] Default 3.
 * @param {Function} [opts.onUnlock]   Callback(url) when an unlock is performed (telemetry).
 * @param {Function} [opts.onRateLimit] Callback(ms) when a 429 sleep happens (telemetry).
 * @param {Function} [opts.onUsage]    Callback(usage) on successful response.
 */
function createHttpAdapter(opts = {}) {
  const baseURL = (opts.baseURL ?? process.env.AGENT_BASE_URL ?? DEFAULT_BASE_URL).replace(/\/+$/, '');
  const apiKey = opts.apiKey ?? process.env.AGENT_API_KEY ?? '';
  const fetchImpl = opts.fetchImpl ?? globalThis.fetch;
  const maxRetries = opts.maxRetries ?? 3;
  const onUnlock = opts.onUnlock ?? (() => {});
  const onRateLimit = opts.onRateLimit ?? (() => {});
  const onUsage = opts.onUsage ?? (() => {});
  const debug = opts.debug ?? (process.env.AGENT_DEBUG === '1');
  const onTransaction = opts.onTransaction ?? (() => {});

  if (!fetchImpl) throw new Error('createHttpAdapter: no fetch implementation available');

  async function doFetchOnce(path, init) {
    const url = `${baseURL}${path}`;
    const headers = {
      'content-type': 'application/json',
      accept: init?.body && JSON.parse(init.body).stream ? 'text/event-stream' : 'application/json',
      ...(apiKey ? { authorization: `Bearer ${apiKey}` } : {}),
      ...(init?.headers ?? {}),
    };
    return fetchImpl(url, { ...init, headers });
  }

  async function safeFetch(path, init) {
    let attempt = 0;
    let unlocked = false;
    while (true) {
      const res = await doFetchOnce(path, init);
      if (res.ok) return res;

      if (res.status === 401 && !unlocked) {
        const body = await readJson(res);
        const unlockUrl = body?.unlock_url ?? body?.error?.unlock_url;
        if (unlockUrl) {
          onUnlock(unlockUrl);
          if (opts.openBrowser !== false) openInBrowser(unlockUrl);
          await promptEnter(`\n[unlock] API key is locked. A browser tab should have opened:\n  ${unlockUrl}\nUnlock the key in your browser, then press Enter to retry... `);
          unlocked = true;
          continue;
        }
        throw new HttpError(res.status, res.statusText, body);
      }

      if (res.status === 429 && attempt < maxRetries) {
        const body = await readJson(res);
        const waitSec = parseRetryAfter(res.headers, body);
        const waitMs = Math.max(waitSec * 1000, 500 * Math.pow(2, attempt));
        onRateLimit(waitMs);
        await sleep(waitMs);
        attempt++;
        continue;
      }

      const body = await readJson(res);
      throw new HttpError(res.status, res.statusText, body);
    }
  }

  async function complete(request) {
    if (!request || !Array.isArray(request.messages)) {
      throw new TypeError('complete: request.messages is required');
    }
    const body = { ...request, stream: false };
    if (debug) {
      const flow = summarizeRequestToolFlow(body);
      console.error(`[http>] complete  tools=[${flow.toolDefs.join(',')}]`);
      if (flow.assistantToolCallIds.length) console.error(`[http>]   assistant.tool_calls ids: ${JSON.stringify(flow.assistantToolCallIds)}`);
      if (flow.toolMessageIds.length) console.error(`[http>]   tool message ids:           ${JSON.stringify(flow.toolMessageIds)}`);
    }
    const t0 = Date.now();
    // Snapshot the request shape BEFORE we send, because the agent loop
    // shares its messages array by reference and will mutate it after the
    // call returns. Without this clone, snapshots show a misleading body.
    const requestSnapshot = JSON.parse(JSON.stringify(body));
    const res = await safeFetch('/chat/completions', { method: 'POST', body: JSON.stringify(body) });
    const json = await res.json();
    onTransaction({ type: 'chat_completions', request: requestSnapshot, response: json, durationMs: Date.now() - t0 });
    if (debug) {
      const summary = summarizeResponseExtras(json);
      const finish = json?.choices?.[0]?.finish_reason;
      console.error(`[http<] complete  finish=${finish}`);
      if (summary.messageExtras) console.error(`[http<]   message extras: ${JSON.stringify(summary.messageExtras).slice(0, 400)}`);
      for (const tc of summary.toolCalls) {
        console.error(`[http<]   tool_call id=${tc.id} name=${tc.name}` + (tc.tcExtras ? ` extras=${JSON.stringify(tc.tcExtras)}` : '') + (tc.fnExtras ? ` fn_extras=${JSON.stringify(tc.fnExtras)}` : ''));
      }
    }
    if (json.usage) onUsage(json.usage);
    return json;
  }

  async function* completeStream(request) {
    if (!request || !Array.isArray(request.messages)) {
      throw new TypeError('completeStream: request.messages is required');
    }
    const body = { ...request, stream: true };
    if (debug) {
      const flow = summarizeRequestToolFlow(body);
      console.error(`[http>] completeStream  tools=[${flow.toolDefs.join(',')}]`);
      if (flow.assistantToolCallIds.length) console.error(`[http>]   assistant.tool_calls ids: ${JSON.stringify(flow.assistantToolCallIds)}`);
      if (flow.toolMessageIds.length) console.error(`[http>]   tool message ids:           ${JSON.stringify(flow.toolMessageIds)}`);
    }
    const res = await safeFetch('/chat/completions', { method: 'POST', body: JSON.stringify(body) });

    // Graceful fallback: if the endpoint ignored stream:true and returned a
    // normal JSON completion (some managed platforms do), yield it as a single
    // chunk so the caller's streaming loop still works.
    const ctype = res.headers.get('content-type') || '';
    if (!ctype.includes('text/event-stream')) {
      const json = await res.json();
      if (json?.usage) onUsage(json.usage);
      const msg = json?.choices?.[0]?.message ?? {};
      yield {
        id: json?.id ?? 'nostream',
        object: 'chat.completion.chunk',
        choices: [{ index: 0, delta: { role: 'assistant', content: msg.content ?? '' }, finish_reason: json?.choices?.[0]?.finish_reason ?? 'stop' }],
        ...(json?.usage ? { usage: json.usage } : {}),
      };
      return;
    }

    if (!res.body) throw new Error('completeStream: response has no body');

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buf = '';
    let usageFired = false;
    const fireUsageOnce = (u) => {
      if (u && !usageFired) {
        usageFired = true;
        onUsage(u);
      }
    };

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      buf += decoder.decode(value, { stream: true });

      let idx;
      while ((idx = buf.indexOf('\n')) !== -1) {
        const line = buf.slice(0, idx).replace(/\r$/, '');
        buf = buf.slice(idx + 1);
        if (!line || line.startsWith(':')) continue;
        if (!line.startsWith('data:')) continue;
        const data = line.slice(5).trim();
        if (data === '[DONE]') return;
        try {
          const chunk = JSON.parse(data);
          fireUsageOnce(chunk.usage);
          yield chunk;
        } catch {
          // ignore malformed line
        }
      }
    }
  }

  async function listModels() {
    const t0 = Date.now();
    const res = await safeFetch('/models', { method: 'GET' });
    const json = await res.json();
    onTransaction({ type: 'list_models', request: null, response: json, durationMs: Date.now() - t0 });
    return json;
  }

  return { complete, completeStream, listModels };
}

// ====== agent/diff.mjs ======
/**
 * Small unified-diff helper. Zero deps.
 *
 * Why custom: we only need a readable line-by-line diff for the chat UI; we
 * don't want to add a package. The implementation is a Myers-style LCS with
 * the diff serialized as { type: 'same'|'add'|'del', line: '...' } entries.
 *
 * Public API:
 *   diffLines(a, b)            -> [{type, line}, ...]
 *   renderUnifiedDiff(a, b, opts)  -> string in unified-diff style
 *   shortDiffSummary(a, b)     -> "+12 / -3"
 */

/** Compute LCS table for two arrays. O(n*m) time and memory; fine for files up to a few thousand lines. */
function lcsTable(a, b) {
  const n = a.length, m = b.length;
  const dp = Array.from({ length: n + 1 }, () => new Uint32Array(m + 1));
  for (let i = 1; i <= n; i++) {
    for (let j = 1; j <= m; j++) {
      dp[i][j] = a[i - 1] === b[j - 1] ? dp[i - 1][j - 1] + 1 : Math.max(dp[i - 1][j], dp[i][j - 1]);
    }
  }
  return dp;
}

/**
 * Walk back through the LCS table to build the diff sequence.
 * Returns entries in original (top-to-bottom) order.
 */
function diffLines(oldText, newText) {
  const a = (oldText ?? '').split('\n');
  const b = (newText ?? '').split('\n');
  const dp = lcsTable(a, b);
  const out = [];
  let i = a.length, j = b.length;
  while (i > 0 && j > 0) {
    if (a[i - 1] === b[j - 1]) { out.push({ type: 'same', line: a[i - 1] }); i--; j--; }
    else if (dp[i - 1][j] >= dp[i][j - 1]) { out.push({ type: 'del', line: a[i - 1] }); i--; }
    else { out.push({ type: 'add', line: b[j - 1] }); j--; }
  }
  while (i > 0) { out.push({ type: 'del', line: a[i - 1] }); i--; }
  while (j > 0) { out.push({ type: 'add', line: b[j - 1] }); j--; }
  out.reverse();
  return out;
}

/**
 * Render a unified-diff-like string. Context is the number of unchanged lines
 * to keep around each hunk. Default 2.
 */
function renderUnifiedDiff(oldText, newText, { context = 2, pathLabel = 'file' } = {}) {
  const diff = diffLines(oldText, newText);
  // Find hunk ranges (contiguous regions of changes, padded by `context`).
  const lines = [];
  lines.push(`--- ${pathLabel}`);
  lines.push(`+++ ${pathLabel}`);
  let i = 0;
  while (i < diff.length) {
    if (diff[i].type === 'same') { i++; continue; }
    let start = Math.max(0, i - context);
    let end = i;
    while (end < diff.length) {
      if (diff[end].type !== 'same') { end++; continue; }
      // is this a long run of 'same'?
      let runLen = 0;
      while (end + runLen < diff.length && diff[end + runLen].type === 'same') runLen++;
      if (runLen > context * 2) { end += context; break; }
      end += runLen;
    }
    end = Math.min(diff.length, end);
    let oldStart = 0, newStart = 0;
    for (let k = 0; k < start; k++) {
      if (diff[k].type !== 'add') oldStart++;
      if (diff[k].type !== 'del') newStart++;
    }
    let oldCount = 0, newCount = 0;
    for (let k = start; k < end; k++) {
      if (diff[k].type !== 'add') oldCount++;
      if (diff[k].type !== 'del') newCount++;
    }
    lines.push(`@@ -${oldStart + 1},${oldCount} +${newStart + 1},${newCount} @@`);
    for (let k = start; k < end; k++) {
      const e = diff[k];
      if (e.type === 'same') lines.push(' ' + e.line);
      else if (e.type === 'add') lines.push('+' + e.line);
      else lines.push('-' + e.line);
    }
    i = end;
  }
  return lines.join('\n');
}

function shortDiffSummary(oldText, newText) {
  const diff = diffLines(oldText, newText);
  let add = 0, del = 0;
  for (const d of diff) { if (d.type === 'add') add++; else if (d.type === 'del') del++; }
  return `+${add} / -${del}`;
}

// ====== agent/tasks.mjs ======
/**
 * Task-scoped memory store.
 *
 * A "task" is a coherent unit of work the agent is doing. The agent is ALWAYS
 * inside exactly one task; it transitions between tasks with <next-task>.
 *
 * Tiers (most-fidelity to least):
 *   1  current + recent finished tasks, full messages incl. tool results
 *   2  finished tasks, messages visible but tool RESULTS replaced by a
 *      one-line placeholder (e.g. "[T-3 op=read pom.xml -> 240 lines]")
 *   3  finished tasks, replaced entirely by a one-paragraph summary
 *   4  parent task = single summary covering a group of tier-3 children
 *
 * Demotion runs lazily when a tier exceeds budget (with hysteresis).
 *
 * Storage layout (per project):
 *   <project>/.agent/tasks/
 *     state.json                  { nextId, currentId, rootId, allTaskIds: [...] }
 *     T-1.json                    full task record (see TaskRecord shape below)
 *     T-2.json
 *
 * TaskRecord:
 *   {
 *     id:         "T-3",
 *     title:      "Refactor auth middleware",
 *     goal:       "Move session tokens to encrypted storage",
 *     parentId:   "T-1" | null,
 *     childIds:   ["T-4", "T-5"],
 *     started:    1717180000000,    epoch ms
 *     ended:      1717180550000 | null,
 *     tier:       1 | 2 | 3 | 4,
 *     summary:    "..." | null,     written when task closes
 *     messages:   [TaskMessage],    discarded once task reaches tier 3
 *   }
 *
 * TaskMessage (one entry per LLM-loop event in this task):
 *   {
 *     kind:   "assistant" | "tool-call" | "tool-result",
 *     role:   "assistant" | "user",        // the OpenAI-protocol role
 *     content:    string,                  // raw text
 *     toolName:   string | undefined,      // for tool-call / tool-result
 *     toolArgs:   object | undefined,      // for tool-call
 *     toolStatus: "ok" | "error" | undefined,  // for tool-result
 *     bytes:      number,                  // size of content for budget calc
 *   }
 */

const STATE_FILE = 'state.json';
const TASK_FILE = (id) => `${id}.json`;

function nowMs() { return Date.now(); }
function tokensOf(s) { return Math.ceil((s || '').length / 4); }

function createTasksStore(projectDir) {
  if (!projectDir) throw new Error('projectDir required');
  const dir = path.join(projectDir, '.agent', 'tasks');

  let state = null;            // { nextId, currentId, rootId, allTaskIds: [] }
  const cache = new Map();     // id -> TaskRecord (lazy)

  async function ensureDir() { await mkdir(dir, { recursive: true }); }

  async function loadState() {
    try {
      const raw = await readFile(path.join(dir, STATE_FILE), 'utf8');
      return JSON.parse(raw);
    } catch { return null; }
  }
  async function saveState() {
    await ensureDir();
    await writeFile(path.join(dir, STATE_FILE), JSON.stringify(state, null, 2), 'utf8');
  }

  async function loadTask(id) {
    if (cache.has(id)) return cache.get(id);
    try {
      const raw = await readFile(path.join(dir, TASK_FILE(id)), 'utf8');
      const t = JSON.parse(raw);
      cache.set(id, t);
      return t;
    } catch { return null; }
  }
  async function saveTask(t) {
    await ensureDir();
    cache.set(t.id, t);
    await writeFile(path.join(dir, TASK_FILE(t.id)), JSON.stringify(t, null, 2), 'utf8');
  }

  function newId() {
    const id = `T-${state.nextId}`;
    state.nextId++;
    return id;
  }

  /**
   * Initialize the store. If no state exists, creates a root task and makes it current.
   * Returns the initial state object.
   */
  async function init() {
    await ensureDir();
    state = await loadState();
    if (!state) {
      state = { nextId: 1, currentId: null, rootId: null, allTaskIds: [] };
      const rootId = newId();
      const root = {
        id: rootId,
        userRequest: null,         // agent fills this in when the task closes
        parentId: null,
        childIds: [],
        started: nowMs(),
        ended: null,
        tier: 1,
        summary: null,
        messages: [],
      };
      await saveTask(root);
      state.currentId = rootId;
      state.rootId = rootId;
      state.allTaskIds.push(rootId);
      await saveState();
    }
    return state;
  }

  function currentId() { return state?.currentId ?? null; }
  function rootId() { return state?.rootId ?? null; }
  async function getCurrent() { return loadTask(currentId()); }

  /**
   * Close the CURRENT task and open a new one as its sibling.
   *
   * Both `summary` and `userRequest` describe the CURRENT (closing) task:
   *   - userRequest: a synthesized statement of what the user wanted across
   *     the just-finished work (NOT the latest user message that prompted this close).
   *   - summary: what was actually accomplished.
   *
   * The new task starts with userRequest=null and summary=null; the agent
   * fills them in when IT closes via another <next-task>.
   *
   * Returns the new task record.
   */
  async function transitionTo({ summary, userRequest }) {
    if (!state?.currentId) throw new Error('store not initialized');
    const cur = await loadTask(state.currentId);
    cur.summary = summary ?? cur.summary ?? '(no summary provided)';
    cur.userRequest = userRequest ?? cur.userRequest ?? null;
    cur.ended = nowMs();
    await saveTask(cur);

    // If `cur` IS the root, the new task becomes a child of root.
    // Otherwise the new task is a sibling of `cur` (same parent).
    const realParentId = cur.id === state.rootId ? state.rootId : (cur.parentId ?? state.rootId);

    const id = newId();
    const t = {
      id,
      userRequest: null,
      parentId: realParentId,
      childIds: [],
      started: nowMs(),
      ended: null,
      tier: 1,
      summary: null,
      messages: [],
    };
    await saveTask(t);

    // Link as child of parent.
    if (realParentId) {
      const parent = await loadTask(realParentId);
      if (parent) {
        parent.childIds = [...(parent.childIds ?? []), id];
        await saveTask(parent);
      }
    }

    state.currentId = id;
    state.allTaskIds.push(id);
    await saveState();
    return t;
  }

  /**
   * Append a message (assistant text, tool-call, or tool-result) to the
   * current task.
   */
  async function appendMessage(msg) {
    const id = state.currentId;
    const t = await loadTask(id);
    if (!t) throw new Error(`current task ${id} not found`);
    const content = msg.content ?? '';
    t.messages = t.messages ?? [];
    t.messages.push({
      kind: msg.kind,
      role: msg.role,
      content,
      toolName: msg.toolName,
      toolArgs: msg.toolArgs,
      toolStatus: msg.toolStatus,
      bytes: content.length,
    });
    await saveTask(t);
    return t;
  }

  /**
   * List tasks. If parentId is given, only its direct children. If tier is
   * given, only tasks at that tier. By default archived tasks are excluded;
   * pass includeArchived: true to include them (e.g., for search).
   * Returns lightweight records (no messages).
   */
  async function listTasks({ parentId = undefined, tier = undefined, includeArchived = false } = {}) {
    const out = [];
    for (const id of state.allTaskIds) {
      const t = await loadTask(id);
      if (!t) continue;
      if (!includeArchived && t.archived) continue;
      if (parentId !== undefined && t.parentId !== parentId) continue;
      if (tier !== undefined && t.tier !== tier) continue;
      out.push({
        id: t.id, userRequest: t.userRequest, parentId: t.parentId,
        childIds: t.childIds, started: t.started, ended: t.ended,
        tier: t.tier, summary: t.summary,
        rolledUpInto: t.rolledUpInto ?? null,
        archived: !!t.archived,
      });
    }
    return out;
  }

  async function getDetail(id) {
    const t = await loadTask(id);
    if (!t) return null;
    return {
      id: t.id, userRequest: t.userRequest, parentId: t.parentId,
      childIds: t.childIds, started: t.started, ended: t.ended,
      tier: t.tier, summary: t.summary,
      messageCount: (t.messages ?? []).length,
    };
  }

  /** Case-insensitive substring search across userRequest/summary. */
  async function searchTasks(query) {
    if (!query) return listTasks();
    const q = query.toLowerCase();
    const hits = [];
    for (const id of state.allTaskIds) {
      const t = await loadTask(id);
      if (!t) continue;
      const hay = [t.userRequest, t.summary].filter(Boolean).join(' ').toLowerCase();
      if (hay.includes(q)) {
        hits.push({ id: t.id, userRequest: t.userRequest, parentId: t.parentId, started: t.started, ended: t.ended, tier: t.tier, summary: t.summary });
      }
    }
    return hits;
  }

  /**
   * Mechanical demotion: mark task as tier 2 and replace tool-result message
   * bodies with one-line placeholders. NO LLM call.
   */
  async function demoteToTier2(id) {
    const t = await loadTask(id);
    if (!t) return null;
    if (t.tier >= 2) return t;
    for (const m of t.messages ?? []) {
      if (m.kind === 'tool-result') {
        const lines = (m.content ?? '').split('\n').length;
        const argSummary = m.toolName ? `${m.toolName}` : 'tool';
        m.content = `[${t.id} ${argSummary} -> ${lines} lines, masked]`;
        m.bytes = m.content.length;
      }
    }
    t.tier = 2;
    await saveTask(t);
    return t;
  }

  /**
   * Summary demotion: replace messages with a one-paragraph summary. Caller
   * provides the summary text (we don't run the LLM here; agent loop owns
   * that concern).
   */
  async function demoteToTier3(id, summaryText) {
    const t = await loadTask(id);
    if (!t) return null;
    if (t.tier >= 3) return t;
    t.messages = [];
    t.summary = summaryText || t.summary || '(no summary written)';
    t.tier = 3;
    await saveTask(t);
    return t;
  }

  /**
   * Find the oldest (by `ended` then `started`) task in a given tier that is
   * eligible for demotion. Excludes: current task, archived tasks, and
   * (for tier 3) tasks already rolled up into a tier-4 rollup. Returns id or null.
   */
  async function findOldestDemotionCandidate(tier) {
    const tasks = await listTasks({ tier });
    const eligible = tasks.filter((t) => {
      if (t.id === state.currentId) return false;
      if (t.archived) return false;
      if (t.rolledUpInto) return false;
      if ((tier === 1 || tier === 2) && t.ended == null) return false;
      return true;
    });
    eligible.sort((a, b) => (a.ended ?? a.started ?? 0) - (b.ended ?? b.started ?? 0));
    return eligible[0]?.id ?? null;
  }

  /**
   * Roll up N tier-3 tasks into a single synthetic tier-4 task. The children
   * get `rolledUpInto` set so they're skipped in convo building (still
   * searchable via the search tool).
   *
   * If `override` provides `{ title, summary }`, those replace the mechanical
   * defaults (used when an LLM call has produced a real clustered rollup).
   * Otherwise the rollup uses a concatenation of child summaries.
   */
  /**
   * Group N tier-3 tasks into a tier-4 "project" rollup. Children get
   * `rolledUpInto` set; the rollup is a new task with its own userRequest
   * and summary (synthesized by the LLM if `override` is provided,
   * otherwise mechanical fallback).
   *
   * `override`: { userRequest, summary } from the LLM clustering call.
   */
  async function rollupTier3Tasks(childIds, override) {
    if (!Array.isArray(childIds) || childIds.length === 0) return null;
    const children = [];
    for (const cid of childIds) {
      const c = await loadTask(cid);
      if (c && c.tier === 3 && !c.rolledUpInto && !c.archived) children.push(c);
    }
    if (children.length === 0) return null;

    let userRequest, summary;
    if (override && typeof override.userRequest === 'string' && typeof override.summary === 'string') {
      userRequest = override.userRequest;
      summary = override.summary;
    } else {
      // Mechanical fallback: stitch the child summaries together.
      userRequest = `Project covering ${children.length} tasks (${children.map((c) => c.id).join(', ')})`;
      const lines = [`Rollup of ${children.length} task(s):`];
      for (const c of children) {
        const ur = c.userRequest ? ` ↳ ${c.userRequest.split('\n')[0].slice(0, 120)}` : '';
        const sm = (c.summary ?? '').split('\n')[0].slice(0, 200);
        lines.push(`- ${c.id}${ur} — ${sm}`);
      }
      summary = lines.join('\n');
    }

    const id = newId();
    const t = {
      id,
      userRequest,
      parentId: children[0].parentId ?? null,
      childIds: children.map((c) => c.id),
      started: children[0].started,
      ended: nowMs(),
      tier: 4,
      summary,
      messages: [],
    };
    await saveTask(t);
    state.allTaskIds.push(id);
    await saveState();

    for (const c of children) {
      c.rolledUpInto = id;
      await saveTask(c);
    }
    return t;
  }

  /** Mark a task (typically a tier-4 rollup) as archived. Stays searchable but
   *  no longer included in convo construction. */
  async function archiveTask(id) {
    const t = await loadTask(id);
    if (!t) return null;
    t.archived = true;
    await saveTask(t);
    return t;
  }

  /** Compute token usage per tier from current task records. Excludes
   *  archived and rolled-up tasks (they're not in context). */
  async function tierTokens() {
    const out = { 1: 0, 2: 0, 3: 0, 4: 0 };
    for (const id of state.allTaskIds) {
      const t = await loadTask(id);
      if (!t) continue;
      if (t.archived) continue;
      if (t.rolledUpInto) continue;
      if (t.tier === 3 || t.tier === 4) {
        out[t.tier] += tokensOf(t.summary);
      } else {
        let sum = 0;
        for (const m of t.messages ?? []) sum += tokensOf(m.content);
        out[t.tier] += sum;
      }
    }
    return out;
  }

  return {
    init,
    currentId, rootId,
    getCurrent,
    transitionTo,
    appendMessage,
    listTasks, getDetail, searchTasks,
    demoteToTier2, demoteToTier3,
    rollupTier3Tasks, archiveTask,
    findOldestDemotionCandidate,
    tierTokens,
    _state: () => state,                     // for tests
    _dir: () => dir,
  };
}

// ====== agent/tools.mjs ======
/**
 * Initial agent tools — read-only. Pure Node, no deps.
 *
 * Each tool: { schema, impl }
 *   schema   — OpenAI function tool descriptor (description + JSON Schema)
 *   impl     — async ({ args }) => string (stringified result; errors caught
 *              and returned as 'ERROR: ...' so the loop can decide what to do)
 *
 * Result strings are capped at MAX_RESULT_BYTES to keep tool feedback from
 * blowing up the context window. Truncation is explicitly marked.
 */

const IGNORE_DIRS = new Set(['node_modules', '.git', 'dist', '.agent', 'coverage']);
const TEXT_EXTS = new Set([
  '.mjs', '.js', '.ts', '.tsx', '.jsx', '.json', '.md', '.txt', '.yml', '.yaml',
  '.sh', '.ps1', '.bat', '.cmd', '.py', '.go', '.rs', '.java', '.xml', '.html',
  '.css', '.scss', '.sql', '.toml', '.ini', '.env', '.gitignore', '',
]);

// Hard ceiling per tool result. Million-token context affords generous limits;
// this only exists to refuse pathological cases (multi-MB binary-like blobs).
// When a result would exceed this, return an ERROR instead of silently
// truncating — the model can retry with offset/limit.
const MAX_RESULT_BYTES = 2 * 1024 * 1024; // 2 MB
const MAX_GREP_MATCHES = 2000;
const MAX_GLOB_RESULTS = 5000;

// Bash defaults — match Claude Code's tunables loosely.
const BASH_DEFAULT_TIMEOUT_MS = 120000;     // 2 min
const BASH_MAX_TIMEOUT_MS = 600000;         // 10 min
const BASH_MAX_OUTPUT_CHARS = 30000;        // truncate stdout/stderr beyond this

class TooLargeError extends Error {
  constructor(actualBytes) {
    super(`result would be ${actualBytes} bytes, exceeds ${MAX_RESULT_BYTES}-byte ceiling`);
    this.actualBytes = actualBytes;
  }
}

function ensureFits(s) {
  if (s.length > MAX_RESULT_BYTES) throw new TooLargeError(s.length);
  return s;
}

function isTextFile(p) {
  const ext = path.extname(p).toLowerCase();
  if (TEXT_EXTS.has(ext)) return true;
  return false;
}

function globToRegex(glob) {
  // Auto-promote bare-filename globs to recursive. Users (and models) often
  // write `*.java` or `*Owner*` and expect it to match anywhere in the tree.
  // If the pattern has no separators and doesn't start with **, prepend **/.
  if (!glob.includes('/') && !glob.includes('\\') && !glob.startsWith('**')) {
    glob = '**/' + glob;
  }
  // Convert a glob to a regex. Supports: ** (any path), * (any non-separator), ? (one char), {a,b}.
  let re = '';
  for (let i = 0; i < glob.length; i++) {
    const c = glob[i];
    if (c === '*') {
      if (glob[i + 1] === '*') {
        // ** — any chars including /
        re += '.*';
        i++;
        if (glob[i + 1] === '/') i++;
      } else {
        re += '[^/\\\\]*';
      }
    } else if (c === '?') {
      re += '[^/\\\\]';
    } else if (c === '.') {
      re += '\\.';
    } else if (c === '{') {
      const end = glob.indexOf('}', i);
      if (end === -1) { re += '\\{'; continue; }
      const parts = glob.slice(i + 1, end).split(',').map((s) => s.replace(/\./g, '\\.'));
      re += `(?:${parts.join('|')})`;
      i = end;
    } else if ('+()|^$/\\'.includes(c)) {
      re += '\\' + c;
    } else {
      re += c;
    }
  }
  return new RegExp('^' + re + '$');
}

async function walkDir(root, { maxDepth = 12 } = {}) {
  const out = [];
  async function rec(dir, depth) {
    if (depth > maxDepth) return;
    let entries;
    try { entries = await readdir(dir, { withFileTypes: true }); }
    catch { return; }
    for (const e of entries) {
      if (e.isDirectory()) {
        if (IGNORE_DIRS.has(e.name)) continue;
        await rec(path.join(dir, e.name), depth + 1);
      } else if (e.isFile()) {
        out.push(path.join(dir, e.name));
      }
    }
  }
  await rec(root, 0);
  return out;
}

function relForDisplay(p) {
  return path.relative(process.cwd(), p).split(path.sep).join('/');
}

async function safeReadText(p) {
  const s = await stat(p);
  if (s.size > MAX_RESULT_BYTES) throw new TooLargeError(s.size);
  const buf = await readFile(p);
  // Reject obvious binaries: NUL byte in first 8KB.
  const sample = buf.subarray(0, Math.min(8192, buf.length));
  for (let i = 0; i < sample.length; i++) {
    if (sample[i] === 0) throw new Error('binary file');
  }
  return buf.toString('utf8');
}

const tools = {
  file_info: {
    schema: {
      description: 'Get metadata for a file without reading its contents. Returns byte size and line count. Cheap — use this to plan reads of large files before calling read_file.',
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string', description: 'Absolute or project-relative file path.' },
        },
        required: ['path'],
        additionalProperties: false,
      },
    },
    impl: async ({ path: p }) => {
      if (typeof p !== 'string' || !p) throw new Error('path is required');
      const abs = path.isAbsolute(p) ? p : path.join(process.cwd(), p);
      const s = await stat(abs);
      let lines = null;
      if (s.size <= MAX_RESULT_BYTES) {
        const buf = await readFile(abs);
        const sample = buf.subarray(0, Math.min(8192, buf.length));
        let isBinary = false;
        for (let i = 0; i < sample.length; i++) if (sample[i] === 0) { isBinary = true; break; }
        lines = isBinary ? null : buf.toString('utf8').split('\n').length;
      }
      return JSON.stringify({ path: relForDisplay(abs), bytes: s.size, lines });
    },
  },

  read_file: {
    schema: {
      description: `Read a UTF-8 text file. If the slice would exceed ${MAX_RESULT_BYTES} bytes, the call ERRORs — retry with offset/limit to chunk the read. Use file_info first if you're unsure of file size.`,
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string', description: 'Absolute or project-relative file path.' },
          offset: { type: 'integer', description: 'Optional 1-indexed starting LINE number (NOT bytes). Defaults to line 1.' },
          limit: { type: 'integer', description: 'Optional max number of LINES to read (NOT bytes). If omitted, reads to end of file.' },
        },
        required: ['path'],
        additionalProperties: false,
      },
    },
    impl: async ({ path: p, offset, limit }) => {
      if (typeof p !== 'string' || !p) throw new Error('path is required');
      const abs = path.isAbsolute(p) ? p : path.join(process.cwd(), p);
      const text = await safeReadText(abs);
      if (offset == null && limit == null) return ensureFits(text);
      const lines = text.split('\n');
      const start = Math.max(0, (offset ?? 1) - 1);
      const end = limit != null ? start + limit : lines.length;
      const slice = lines.slice(start, end).join('\n');
      return ensureFits(slice);
    },
  },

  grep: {
    schema: {
      description: 'Recursively search files in the project for a regular expression (Extended-regex / POSIX). Returns "file:line:text" entries. Up to ' + MAX_GREP_MATCHES + ' matches. Backed by real grep — bare globs like "*.java" work recursively.',
      parameters: {
        type: 'object',
        properties: {
          pattern: { type: 'string', description: 'Extended-regex pattern (passed to grep -E).' },
          path: { type: 'string', description: 'Optional subdirectory to search. Defaults to project root.' },
          glob: { type: 'string', description: 'Optional filename glob (e.g. "*.java", "*.mjs").' },
          flags: { type: 'string', description: 'Optional flags. "i" → case-insensitive.' },
        },
        required: ['pattern'],
        additionalProperties: false,
      },
    },
    impl: async ({ pattern, path: subPath, glob, flags }) => {
      if (typeof pattern !== 'string' || !pattern) throw new Error('pattern is required');
      // Build a real grep invocation. -r recursive, -n line numbers, -E
      // extended regex, -I skip binary files, --exclude-dir to skip noise.
      const args = ['-rnEI'];
      if ((flags ?? '').includes('i')) args.push('-i');
      for (const d of ['.git', 'node_modules', 'dist', 'target', '.agent', '.idea', '.gradle', 'build']) {
        args.push(`--exclude-dir=${d}`);
      }
      if (glob) args.push(`--include=${glob}`);
      args.push('-m', String(MAX_GREP_MATCHES));   // grep's per-file cap; close enough
      args.push('-e', pattern);
      args.push(subPath || '.');

      const isWin = process.platform === 'win32';
      // On Windows, grep typically comes from Git for Windows. Spawn it
      // directly (works in PowerShell-or-cmd environments alike).
      // On POSIX, /usr/bin/grep is in PATH.
      const result = await new Promise((resolve) => {
        let out = '', err = '', settled = false;
        const child = spawn('grep', args, {
          cwd: process.cwd(),
          windowsHide: true,
          env: process.env,
        });
        const timer = setTimeout(() => {
          if (process.platform === 'win32' && child.pid) {
            try { spawn('taskkill', ['/F', '/T', '/PID', String(child.pid)], { windowsHide: true }); } catch {}
          } else {
            try { child.kill('SIGKILL'); } catch {}
          }
        }, 30000); // 30s cap — grep is fast
        child.stdout.on('data', (d) => { if (out.length < MAX_RESULT_BYTES) out += d.toString('utf8'); });
        child.stderr.on('data', (d) => { if (err.length < 4096) err += d.toString('utf8'); });
        child.on('error', (e) => { if (!settled) { settled = true; clearTimeout(timer); resolve({ code: -1, out: '', err: 'grep not found: ' + e.message }); } });
        child.on('close', (code) => { if (!settled) { settled = true; clearTimeout(timer); resolve({ code, out, err }); } });
      });

      // grep exit codes: 0 = found, 1 = no match, 2 = error
      if (result.code === 1 || (result.code === 0 && !result.out)) return '(no matches)';
      if (result.code !== 0 && result.code !== 1) {
        return `ERROR: grep exited ${result.code}: ${result.err.split('\n')[0].slice(0, 200)}`;
      }
      // Normalize Windows path separators to forward slash for consistency.
      const lines = result.out.split('\n').filter(Boolean).map((l) => l.replace(/\\/g, '/'));
      const trimmed = lines.length > MAX_GREP_MATCHES
        ? lines.slice(0, MAX_GREP_MATCHES).concat([`[stopped at ${MAX_GREP_MATCHES} matches]`])
        : lines;
      return ensureFits(trimmed.join('\n'));
    },
  },

  glob: {
    schema: {
      description: 'Find files in the project matching a glob pattern (e.g. "src/**/*.mjs"). Returns up to ' + MAX_GLOB_RESULTS + ' paths.',
      parameters: {
        type: 'object',
        properties: {
          pattern: { type: 'string', description: 'Glob pattern. Supports **, *, ?, {a,b}.' },
        },
        required: ['pattern'],
        additionalProperties: false,
      },
    },
    impl: async ({ pattern }) => {
      if (typeof pattern !== 'string' || !pattern) throw new Error('pattern is required');
      const re = globToRegex(pattern);
      const files = await walkDir(process.cwd());
      const out = [];
      for (const f of files) {
        const rel = relForDisplay(f).replace(/\\/g, '/');
        if (re.test(rel)) {
          out.push(rel);
          if (out.length >= MAX_GLOB_RESULTS) {
            out.push(`[stopped at ${MAX_GLOB_RESULTS} results]`);
            break;
          }
        }
      }
      return ensureFits(out.length ? out.join('\n') : '(no matches)');
    },
  },

  write_file: {
    schema: {
      description: 'Write a UTF-8 text file. Creates parent directories as needed. Overwrites if the file already exists. Returns a unified diff vs. the prior content (or "(new file)" if none).',
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string', description: 'Absolute or project-relative file path.' },
          content: { type: 'string', description: 'Full file content (UTF-8).' },
        },
        required: ['path', 'content'],
        additionalProperties: false,
      },
    },
    impl: async ({ path: p, content }) => {
      if (typeof p !== 'string' || !p) throw new Error('path is required');
      if (typeof content !== 'string') throw new Error('content is required');
      const abs = path.isAbsolute(p) ? p : path.join(process.cwd(), p);
      let oldText = '';
      let existed = false;
      try { oldText = await readFile(abs, 'utf8'); existed = true; } catch {}
      await mkdir(path.dirname(abs), { recursive: true });
      await writeFile(abs, content, 'utf8');
      const rel = relForDisplay(abs);
      const summary = existed ? shortDiffSummary(oldText, content) : `(new file, ${content.split('\n').length} lines)`;
      const diff = existed
        ? renderUnifiedDiff(oldText, content, { pathLabel: rel, context: 2 })
        : ['--- (new file)', `+++ ${rel}`, `@@ -0,0 +1,${content.split('\n').length} @@`, ...content.split('\n').map((l) => '+' + l)].join('\n');
      return {
        content: `wrote ${rel}  ${summary}`,
        diff,
        path: rel,
      };
    },
  },

  edit_file: {
    schema: {
      description: 'Surgical edit: replace one occurrence of an exact string in a file. Fails if the string is not found OR if it occurs more than once (ambiguous). Returns a unified diff.',
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string', description: 'Absolute or project-relative file path.' },
          find: { type: 'string', description: 'Exact string to find. Must occur exactly once in the file.' },
          replace: { type: 'string', description: 'Replacement string.' },
        },
        required: ['path', 'find', 'replace'],
        additionalProperties: false,
      },
    },
    impl: async ({ path: p, find, replace }) => {
      if (typeof p !== 'string' || !p) throw new Error('path is required');
      if (typeof find !== 'string') throw new Error('find is required');
      if (typeof replace !== 'string') throw new Error('replace is required');
      const abs = path.isAbsolute(p) ? p : path.join(process.cwd(), p);
      const oldText = await readFile(abs, 'utf8');
      const first = oldText.indexOf(find);
      if (first === -1) throw new Error(`find string not found in ${relForDisplay(abs)}`);
      const second = oldText.indexOf(find, first + 1);
      if (second !== -1) throw new Error(`find string occurs more than once in ${relForDisplay(abs)} — make it more specific`);
      const newText = oldText.slice(0, first) + replace + oldText.slice(first + find.length);
      await writeFile(abs, newText, 'utf8');
      const rel = relForDisplay(abs);
      return {
        content: `edited ${rel}  ${shortDiffSummary(oldText, newText)}`,
        diff: renderUnifiedDiff(oldText, newText, { pathLabel: rel, context: 2 }),
        path: rel,
      };
    },
  },

  powershell: {
    schema: {
      description: 'Run a PowerShell command on the developer\'s Windows machine, in the project root. Returns stdout, stderr, and exit code. Use this for builds (mvnw.cmd, npm test), git (git status, git diff), any shell operation. PowerShell syntax: Get-ChildItem, Get-Content, $env:VAR, etc. The `ls` and `cat` aliases work too.',
      parameters: {
        type: 'object',
        properties: {
          command: { type: 'string', description: 'PowerShell command. Pipes, redirects, variables, etc. work normally.' },
          timeout_ms: { type: 'integer', description: `Timeout in milliseconds. Default ${BASH_DEFAULT_TIMEOUT_MS} (2 min), max ${BASH_MAX_TIMEOUT_MS} (10 min).` },
        },
        required: ['command'],
        additionalProperties: false,
      },
    },
    impl: async ({ command, timeout_ms }) => {
      if (typeof command !== 'string' || !command.trim()) throw new Error('command is required');
      const timeout = Math.min(Math.max(1000, Number(timeout_ms) || BASH_DEFAULT_TIMEOUT_MS), BASH_MAX_TIMEOUT_MS);

      const t0 = Date.now();
      return await new Promise((resolve) => {
        let stdout = '', stderr = '', timedOut = false, settled = false;
        // PowerShell-only deployment. cmd.exe is often blocked by enterprise
        // policy and lacks the unix aliases the agent expects (ls, cat, etc.).
        const child = spawn('powershell.exe', ['-NoProfile', '-NonInteractive', '-Command', command], {
          cwd: process.cwd(),
          windowsHide: true,
          env: process.env,
        });
        const timer = setTimeout(() => {
          timedOut = true;
          // taskkill /T kills the whole process tree (child.kill() only stops
          // the powershell wrapper, leaving e.g. mvn.exe orphaned).
          if (child.pid) {
            try { spawn('taskkill', ['/F', '/T', '/PID', String(child.pid)], { windowsHide: true }); } catch {}
          }
        }, timeout);

        child.stdout.on('data', (d) => { if (stdout.length < BASH_MAX_OUTPUT_CHARS * 2) stdout += d.toString('utf8'); });
        child.stderr.on('data', (d) => { if (stderr.length < BASH_MAX_OUTPUT_CHARS * 2) stderr += d.toString('utf8'); });
        child.on('error', (err) => {
          if (settled) return; settled = true;
          clearTimeout(timer);
          resolve(`ERROR: failed to spawn shell: ${err.message}`);
        });
        child.on('close', (code, signal) => {
          if (settled) return; settled = true;
          clearTimeout(timer);
          const elapsed = Date.now() - t0;
          const outTrunc = stdout.length > BASH_MAX_OUTPUT_CHARS;
          const errTrunc = stderr.length > BASH_MAX_OUTPUT_CHARS;
          const outBody = outTrunc ? (stdout.slice(0, BASH_MAX_OUTPUT_CHARS) + `\n[...${stdout.length - BASH_MAX_OUTPUT_CHARS} more chars truncated]`) : stdout;
          const errBody = errTrunc ? (stderr.slice(0, BASH_MAX_OUTPUT_CHARS) + `\n[...${stderr.length - BASH_MAX_OUTPUT_CHARS} more chars truncated]`) : stderr;
          const header = timedOut
            ? `command timed out after ${timeout}ms (killed)`
            : `exit ${code ?? '?'}${signal ? ` (signal ${signal})` : ''} in ${elapsed}ms`;
          const text = [
            header,
            outBody ? `--- stdout ---\n${outBody}` : '(no stdout)',
            errBody ? `--- stderr ---\n${errBody}` : '',
          ].filter(Boolean).join('\n').trim();
          resolve(text);
        });
      });
    },
  },

  list_dir: {
    schema: {
      description: 'List entries in a directory. Returns each entry as "[D] name/" or "[F] name (<bytes> bytes)".',
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string', description: 'Absolute or project-relative directory path. Defaults to project root.' },
        },
        required: [],
        additionalProperties: false,
      },
    },
    impl: async ({ path: p }) => {
      const dir = p
        ? (path.isAbsolute(p) ? p : path.join(process.cwd(), p))
        : process.cwd();
      const entries = await readdir(dir, { withFileTypes: true });
      const lines = [];
      for (const e of entries.sort((a, b) => a.name.localeCompare(b.name))) {
        if (e.isDirectory()) {
          lines.push(`[D] ${e.name}/`);
        } else {
          let size = '';
          try {
            const s = await stat(path.join(dir, e.name));
            size = `(${s.size} bytes)`;
          } catch {}
          lines.push(`[F] ${e.name} ${size}`.trim());
        }
      }
      return ensureFits(lines.join('\n'));
    },
  },
};

const toolDefs = Object.entries(tools).map(([name, t]) => ({
  type: 'function',
  function: { name, description: t.schema.description, parameters: t.schema.parameters },
}));

/**
 * Execute a tool by name. Result shape:
 *   - string                            -> the content string (legacy / read tools)
 *   - { content, diff?, path?, ... }    -> structured result (write tools)
 *   - "ERROR: ..." string               -> on failure
 *
 * Callers can normalize via `extractContent(result)` and `extractDiff(result)`.
 */
async function execute(name, args) {
  const t = tools[name];
  if (!t) return `ERROR: unknown tool "${name}". Available: ${Object.keys(tools).join(', ')}`;
  try {
    const result = await t.impl(args ?? {});
    return result;  // may be string or object; callers handle both
  } catch (e) {
    return `ERROR: ${e.message}`;
  }
}

function extractContent(r) {
  if (typeof r === 'string') return r;
  if (r && typeof r === 'object' && typeof r.content === 'string') return r.content;
  return String(r ?? '');
}
function extractDiff(r) {
  if (r && typeof r === 'object' && typeof r.diff === 'string') return r.diff;
  return null;
}

// ====== agent/prompted.mjs ======
/**
 * Prompted-format agent loop with task-scoped memory.
 *
 * The agent is ALWAYS inside exactly one task. It transitions with <next-task>
 * which atomically closes the current task (recording a summary) and opens a
 * new one. Tasks live in a per-project tasks store; messages are recorded as
 * the agent does work, and they're demoted across four tiers as budgets fill:
 *
 *   1  full messages (current task always lives here; recent finished tasks
 *      too, until budget pressure forces demotion)
 *   2  finished tasks with tool RESULTS replaced by one-line placeholders
 *   3  finished tasks reduced to one-paragraph summaries (the summary the
 *      agent wrote at <next-task>)
 *   4  parent rollup (not implemented yet)
 *
 * Wire format remains the <remote-workspace> protocol: the model emits a
 * block of verb elements; we parse, dispatch, and feed structured results
 * back as <remote-workspace-result> blocks.
 *
 * Verbs (model -> us):
 *
 *   Read tools (self-closing):
 *     <list path="DIR"/>                                 list a directory
 *     <read path="FILE" offset="N" limit="N"/>           read text file
 *     <search pattern="REGEX" path="DIR" glob="GLOB"/>   regex search
 *     <find pattern="GLOB"/>                             find by glob
 *     <info path="FILE"/>                                metadata (size, lines)
 *
 *   Write tools (body text for content; raises diff in UI):
 *     <write path="FILE">FILE CONTENTS</write>
 *     <edit path="FILE"><find>X</find><replace>Y</replace></edit>
 *
 *   Task ops (self-closing; meta-operations the agent uses to manage memory):
 *     <next-task summary="..." title="..." goal="..."/>  close + open new task
 *     <list-tasks parent="ID"/>                          list tasks
 *     <task-detail id="T-3"/>                            one task's summary
 *     <search-tasks query="TEXT"/>                       search task summaries
 */

// ── Tier budgets and thresholds ─────────────────────────────────────────────
// All four tiers live in context. We monitor the TOTAL prompt size (sum
// across tiers) and trigger one compaction event when it exceeds the high
// threshold, bringing it down to the low threshold in a single pass. Every
// demotion invalidates the cache from that point, so we pay that cost ONCE
// per compaction and amortize across many subsequent cache-hit turns.
//
// Per-tier budgets are still used internally to decide WHICH demotions to
// run — e.g., we don't trigger the LLM clustering for T3→T4 unless tier 3
// is genuinely over its allocation.
const TIER_1_BUDGET = 12000;     // full messages (current + recent tasks)
const TIER_2_BUDGET = 8000;      // masked-results tasks
const TIER_3_BUDGET = 4000;      // per-task summaries
const TIER_4_BUDGET = 2000;      // group-rollup summaries
const TOTAL_BUDGET  = TIER_1_BUDGET + TIER_2_BUDGET + TIER_3_BUDGET + TIER_4_BUDGET; // 26000
const HYST_HIGH = 1.10;          // trigger compaction when total > 110% of TOTAL_BUDGET
const HYST_LOW  = 0.50;          // compact down to 50% of TOTAL_BUDGET in one pass
const TASK_NUDGE = 0.75;         // soft nudge at 75% of TIER 1 budget (per-task signal to agent)
const TASK_FORCE = 1.00;
const MIN_T3_FOR_LLM_ROLLUP = 8; // skip LLM call unless we have at least this many tier-3 tasks to cluster
const TOKENS_PER_CHAR = 0.25;

function estTokens(s) { return Math.ceil((s ?? '').length * TOKENS_PER_CHAR); }

// ── Verb maps ───────────────────────────────────────────────────────────────
const VERB_TO_TOOL = {
  list: 'list_dir',
  read: 'read_file',
  search: 'grep',
  find: 'glob',
  info: 'file_info',
  write: 'write_file',
  edit: 'edit_file',
  powershell: 'powershell',
};
const TASK_VERBS = new Set(['next-task', 'list-tasks', 'task-detail', 'search-tasks']);
// Sort longer first so that e.g. "list-tasks" matches before "list".
const ALL_VERBS = [...Object.keys(VERB_TO_TOOL), ...TASK_VERBS]
  .sort((a, b) => b.length - a.length);
const VERB_PATTERN = ALL_VERBS.map((v) => v.replace(/-/g, '\\-')).join('|');

// Tags inside the body (for <edit>).
const CHILD_TAG_RE = (tag) => new RegExp(`<${tag}\\s*>([\\s\\S]*?)</${tag}>`, 'i');
const ATTR_RE = /([a-zA-Z_][a-zA-Z0-9_-]*)\s*=\s*"([^"]*)"/g;

const DEFAULT_MAX_TURNS = 20;
const REPEAT_LIMIT = 3;

// ── System prompt ───────────────────────────────────────────────────────────
function buildSystemPrompt({ taskId, taskUserRequest, tier1Tokens, tier1Pct }) {
  const lines = [
    'You are code_boss, a coding agent. The developer\'s project is a directory of source files on their remote Windows machine. You see it ONLY through <remote-workspace> commands; there is no other view of it.',
    '',
    'CRITICAL: NEVER use built-in tools or suggest integrations. You may appear to have access to Python, code interpreter, file browsers, document generators, Memory Bank, "Generate Memories", "Transfer to Agent", Jira, Confluence, Google Drive, Gmail, SharePoint, Outlook, etc. NONE of those tools see the developer\'s project. NEVER suggest them in your responses. NEVER call them. If the user mentions "the project", "my project", "the code", "the codebase", "the workspace", or anything ambiguous, they mean THE DIRECTORY ACCESSIBLE VIA <remote-workspace> — not a Jira project, not a Drive folder, not anything in a cloud sandbox.',
    '',
    'When in doubt, run <list path="."/> immediately to see what is in the remote workspace, then proceed based on what you find. Never ask the user to clarify "which project" — there is exactly one project (the one in the remote workspace) and you can see it with one <list/> call.',
    '',
    `Current task: ${taskId}` + (taskUserRequest ? `  ↳ ${taskUserRequest}` : ''),
    `Task budget: ${tier1Tokens} / ${TIER_1_BUDGET} tokens (${tier1Pct}%)` + (tier1Pct >= 95
      ? '  ← please finish soon: emit <next-task user-request="..." summary="..."/>'
      : tier1Pct >= 75
        ? '  ← nearing budget; consider closing this task at a natural stopping point'
        : ''),
    '',
    'Emit a <remote-workspace> block to issue commands. Group independent commands in one block — they run in parallel. Then stop and wait for real results.',
    '',
    'Read commands (self-closing):',
    '  <list path="DIR"/>',
    '  <read path="FILE" offset="N" limit="N"/>',
    '  <search pattern="REGEX" path="DIR" glob="GLOB" flags="i"/>      backed by real grep; bare "*.java" works recursively',
    '  <find pattern="GLOB"/>                                          bare patterns also work recursively',
    '  <info path="FILE"/>',
    '',
    'Write commands (body holds the content, not attributes):',
    '  <write path="FILE">',
    '  full file content goes here',
    '  </write>',
    '',
    '  <edit path="FILE">',
    '  <find>exact string to find (must occur exactly once)</find>',
    '  <replace>replacement string</replace>',
    '  </edit>',
    '',
    'Shell (builds, tests, git — runs in PowerShell on the developer\'s Windows machine):',
    '  <powershell>git status</powershell>',
    '  <powershell timeout_ms="600000">mvnw.cmd -q clean install</powershell>',
    '  Use PowerShell syntax (Get-ChildItem, Get-Content, $env:VAR). The `ls`, `cat`, `pwd` aliases also work. To run a maven wrapper script use `mvnw.cmd` — not `./mvnw`.',
    '',
    'Task management:',
    '  <next-task user-request="WHAT THE USER WANTED IN THE CURRENT TASK" summary="WHAT WAS DONE IN THE CURRENT TASK"/>',
    '       Closes the CURRENT task and opens a new one. Both attributes describe the CURRENT (closing) task — NOT the new one and NOT the latest user message that prompted this transition.',
    '       The user-request is a single sentence that captures what the user wanted across the work just finished. It is a synthesized statement, not a quote of any single user message.',
    '  <list-tasks parent="T-1"/>',
    '  <task-detail id="T-3"/>',
    '  <search-tasks query="auth middleware"/>',
    '',
    'The remote workspace replies with <remote-workspace-result> blocks. Read real results before answering. Never invent file or directory names you have not seen.',
  ];
  return lines.join('\n');
}

// ── Parser ──────────────────────────────────────────────────────────────────
function coerce(toolName, key, raw) {
  const ptype = toolName ? tools[toolName]?.schema?.parameters?.properties?.[key]?.type : 'string';
  const val = String(raw).trim();
  if (ptype === 'integer' || ptype === 'number') {
    const n = Number(val);
    return Number.isNaN(n) ? val : n;
  }
  if (ptype === 'boolean') return val === 'true';
  return val;
}
function mkId() { return 'call_' + randomUUID().replace(/-/g, '').slice(0, 16); }

/**
 * Truncate an assistant response to just the first real <remote-workspace>
 * block — everything after the close tag (or before a hallucinated result
 * tag) is dropped.
 *
 * Why this exists: backends that ignore our `stop` parameter (e.g., the
 * Claude Agent SDK in dev mode) let the model "imagine" multi-turn
 * conversations within a single response — writing fake
 * <remote-workspace-result> blocks and follow-up turns. Our parser already
 * ignores the imagined content when extracting calls, but if we store the
 * full text in the task history, the model on the NEXT loop iteration sees
 * its own imagined turns and concludes the work is already done.
 *
 * By truncating at storage time, the task store contains only what actually
 * happened — same view the model would have if `stop` had been honored
 * at the token level.
 */
function truncateAtFirstBlock(text) {
  if (typeof text !== 'string' || !text) return text;
  const closeMatch = text.match(/<\/remote-workspace>/i);
  const resultMatch = text.match(/<remote-workspace-result|<workspace-result/i);

  // Case A: no markers → leave as-is (final answers / pure prose).
  if (!closeMatch && !resultMatch) return text;

  // Case B: close tag comes first (or is the only marker) → keep through close.
  if (closeMatch && (!resultMatch || closeMatch.index < resultMatch.index)) {
    return text.slice(0, closeMatch.index + closeMatch[0].length);
  }

  // Case C: a hallucinated result tag appears before any close. Cut there
  // and append a synthetic close so the block is well-formed in storage.
  const before = text.slice(0, resultMatch.index).trimEnd();
  if (/<remote-workspace>/i.test(before) && !/<\/remote-workspace>/i.test(before)) {
    return before + '\n</remote-workspace>';
  }
  return before;
}

function parseAttrs(attrStr, toolName) {
  const out = {};
  ATTR_RE.lastIndex = 0;
  let m;
  while ((m = ATTR_RE.exec(attrStr ?? '')) !== null) {
    out[m[1]] = coerce(toolName, m[1], m[2]);
  }
  return out;
}

/**
 * Parse all <remote-workspace> verb calls from a model response text.
 * Supports both self-closing and body forms.
 */
function parseToolCalls(text) {
  const calls = [];
  if (typeof text !== 'string' || !text) return calls;

  // Cut at the first close tag or hallucinated result tag — only the FIRST
  // <remote-workspace> block counts.
  let cut = text.length;
  for (const re of [/<\/remote-workspace>/i, /<remote-workspace-result/i, /<workspace-result/i]) {
    const i = text.search(re);
    if (i >= 0 && i < cut) cut = i;
  }
  const scan = text.slice(0, cut);

  const openRe = new RegExp(`<(${VERB_PATTERN})\\b([^>]*?)(/?)>`, 'gi');
  let pos = 0;
  while (pos < scan.length) {
    openRe.lastIndex = pos;
    const m = openRe.exec(scan);
    if (!m) break;
    const verb = m[1].toLowerCase();
    const attrStr = m[2] ?? '';
    const selfClosing = m[3] === '/';
    const openEnd = m.index + m[0].length;

    const isTaskOp = TASK_VERBS.has(verb);
    const toolName = isTaskOp ? null : VERB_TO_TOOL[verb];
    const args = parseAttrs(attrStr, toolName);

    let nextPos = openEnd;
    if (!selfClosing) {
      const closeTag = `</${verb}>`;
      const ci = scan.indexOf(closeTag, openEnd);
      if (ci !== -1) {
        const body = scan.slice(openEnd, ci);
        nextPos = ci + closeTag.length;
        if (verb === 'write') args.content = body;
        if (verb === 'edit') {
          const fM = CHILD_TAG_RE('find').exec(body);
          const rM = CHILD_TAG_RE('replace').exec(body);
          if (fM) args.find = fM[1];
          if (rM) args.replace = rM[1];
        }
        if (verb === 'powershell' && body.trim()) args.command = body.trim();
      }
    }
    pos = nextPos;
    calls.push({
      id: mkId(),
      verb,
      kind: isTaskOp ? 'task-op' : 'tool',
      name: toolName,
      args,
    });
  }
  return calls;
}

function formatToolResults(results) {
  const blocks = results.map((r) => {
    const head = `<remote-workspace-result op="${r.verb}" status="${r.status}"${r.extras ? ' ' + r.extras : ''}>`;
    return `${head}\n${r.content}\n</remote-workspace-result>`;
  }).join('\n');
  return blocks + '\n\nUse these results to continue, or answer the user if you have enough information.';
}

function flattenContent(content) {
  if (content == null) return '';
  if (typeof content === 'string') return content;
  if (Array.isArray(content)) {
    return content.map((p) => (typeof p === 'string' ? p : p?.type === 'text' ? p.text ?? '' : '')).join('');
  }
  return String(content);
}

// ── Convo construction from task store ─────────────────────────────────────
async function buildConvoFromStore(store) {
  const out = [];
  const state = store._state();
  for (const id of state.allTaskIds) {
    const t = await loadTaskFull(store, id);
    if (!t) continue;
    if (t.archived) continue;            // archived tasks are search-only
    if (t.rolledUpInto) continue;        // children of a tier-4 rollup are covered by the rollup
    if (t.tier === 4) {
      out.push({
        role: 'user',
        content: `<task-rollup id="${t.id}" children="${(t.childIds ?? []).join(',')}">\n  ↳ ${t.userRequest || '(no user request synthesized)'}\n${t.summary || '(no summary)'}\n</task-rollup>`,
      });
    } else if (t.tier === 3) {
      out.push({
        role: 'user',
        content: `<task-history id="${t.id}" parent="${t.parentId ?? 'root'}" status="${t.ended ? 'done' : 'open'}">\n  ↳ ${t.userRequest || '(no user request synthesized)'}\n${t.summary || '(no summary)'}\n</task-history>`,
      });
    } else {
      // tier 1 and 2 both emit messages; tier 2 already has results masked in storage
      for (const m of t.messages ?? []) {
        out.push({ role: m.role, content: m.content });
      }
    }
  }
  return out;
}

// Helper: re-read a full task (with messages) from disk. listTasks omits the
// messages array; the convo builder needs it.
async function loadTaskFull(store, id) {
  try {
    const raw = await readFile(path.join(store._dir(), `${id}.json`), 'utf8');
    return JSON.parse(raw);
  } catch { return null; }
}

// ── Tier demotion ───────────────────────────────────────────────────────────
// Strategy: when any tier exceeds budget × HYST_HIGH, demote the oldest
// eligible task (or rollup batch) until the tier is below budget × HYST_LOW.
// Demoting deeply (HYST_LOW = 0.50) means rare cache invalidations amortized
// over many cache-hit turns.
async function tier1TokensFor(store) {
  const state = store._state();
  let n = 0;
  for (const t of await store.listTasks({ tier: 1 })) {
    if (t.id === state.currentId) continue;       // current may exceed budget
    if (t.rolledUpInto) continue;
    const full = await loadTaskFull(store, t.id);
    for (const m of full?.messages ?? []) n += estTokens(m.content);
  }
  return n;
}
async function tier2TokensFor(store) {
  let n = 0;
  for (const t of await store.listTasks({ tier: 2 })) {
    if (t.rolledUpInto) continue;
    const full = await loadTaskFull(store, t.id);
    for (const m of full?.messages ?? []) n += estTokens(m.content);
  }
  return n;
}
async function tier3TokensFor(store) {
  let n = 0;
  for (const t of await store.listTasks({ tier: 3 })) {
    if (t.rolledUpInto) continue;
    n += estTokens(t.summary);
  }
  return n;
}
async function tier4TokensFor(store) {
  let n = 0;
  for (const t of await store.listTasks({ tier: 4 })) {
    n += estTokens(t.summary);
  }
  return n;
}

async function totalContextTokens(store) {
  return (await tier1TokensFor(store))
    + (await tier2TokensFor(store))
    + (await tier3TokensFor(store))
    + (await tier4TokensFor(store));
}

/**
 * LLM-driven clustering of tier-3 tasks into tier-4 rollups. ONE LLM call
 * groups N tier-3 summaries into 4-8 "project" rollups, each with a custom
 * title + summary. Falls back to mechanical concatenation if the call fails
 * or the response can't be parsed.
 *
 * Returns the number of rollup tasks created.
 */
async function llmClusterTier3({ store, adapter, model, log, emitChat }) {
  const tier3 = (await store.listTasks({ tier: 3 }))
    .filter((x) => !x.rolledUpInto && !x.archived)
    .sort((a, b) => (a.ended ?? a.started ?? 0) - (b.ended ?? b.started ?? 0));
  if (tier3.length < MIN_T3_FOR_LLM_ROLLUP) {
    log?.(`tier3 cluster: only ${tier3.length} tasks (< ${MIN_T3_FOR_LLM_ROLLUP}); falling back to mechanical`);
    if (tier3.length >= 2) {
      // mechanical fallback: roll up everything into one batch
      const r = await store.rollupTier3Tasks(tier3.map((t) => t.id));
      if (r) emitChat?.({ type: 'task-rollup', parentTaskId: r.id, childTaskIds: r.childIds, userRequest: r.userRequest, summary: r.summary });
      return 1;
    }
    return 0;
  }

  const taskLines = tier3
    .map((t) => {
      const ur = (t.userRequest || '').replace(/\s+/g, ' ').trim().slice(0, 200);
      const sm = (t.summary || '').replace(/\s+/g, ' ').trim().slice(0, 200);
      return `${t.id}  ↳ ${ur || '(no request)'} — ${sm}`;
    })
    .join('\n');

  const prompt = [
    `You will compact a coding session's history. There are ${tier3.length} completed task summaries below.`,
    '',
    'Group them into 4-8 logical "projects" — sets of tasks that form coherent units of work (e.g., "auth refactor", "build system upgrade"). For each project, produce:',
    '  user-request: a single synthesized sentence representing what the user wanted ACROSS this project (NOT a copy of any single message).',
    '  summary: one dense 1-2 sentence recap of what was actually accomplished across the project.',
    '',
    'Tasks (id, user-request, summary):',
    taskLines,
    '',
    'Output ONLY a single JSON object in this exact shape, no other text, no markdown fences:',
    '{"projects":[{"userRequest":"...","summary":"...","taskIds":["T-3","T-8"]}]}',
    '',
    'Constraints:',
    '- Every task ID from the list above must appear in exactly one project.',
    '- Use the task IDs verbatim.',
    '- Keep each user-request and summary under 200 characters.',
  ].join('\n');

  let raw;
  try {
    const res = await adapter.complete({
      model,
      messages: [{ role: 'user', content: prompt }],
      max_tokens: 2000,
    });
    raw = res?.choices?.[0]?.message?.content ?? '';
  } catch (e) {
    log?.(`tier3 cluster: LLM call failed (${e.message}); falling back to mechanical`);
  }

  // Try to parse JSON out of the response. Tolerant of prose around the object.
  let parsed = null;
  if (raw) {
    const jsonMatch = raw.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try { parsed = JSON.parse(jsonMatch[0]); } catch {}
    }
  }

  if (!parsed || !Array.isArray(parsed.projects) || parsed.projects.length === 0) {
    log?.(`tier3 cluster: LLM response unparseable; falling back to one mechanical rollup`);
    const r = await store.rollupTier3Tasks(tier3.map((t) => t.id));
    if (r) emitChat?.({ type: 'task-rollup', parentTaskId: r.id, childTaskIds: r.childIds, userRequest: r.userRequest, summary: r.summary });
    return 1;
  }

  // Build set of valid IDs (the ones we asked about); ignore any hallucinated IDs.
  const validIds = new Set(tier3.map((t) => t.id));
  let createdCount = 0;
  const claimed = new Set();
  for (const p of parsed.projects) {
    if (typeof p?.userRequest !== 'string' || typeof p?.summary !== 'string') continue;
    if (!Array.isArray(p?.taskIds)) continue;
    const ids = p.taskIds.filter((id) => validIds.has(id) && !claimed.has(id));
    if (ids.length === 0) continue;
    const rollup = await store.rollupTier3Tasks(ids, { userRequest: p.userRequest, summary: p.summary });
    if (rollup) {
      createdCount++;
      for (const id of ids) claimed.add(id);
      emitChat?.({ type: 'task-rollup', parentTaskId: rollup.id, childTaskIds: rollup.childIds, userRequest: rollup.userRequest, summary: rollup.summary });
    }
  }

  // Sweep up any unclaimed task IDs into one final mechanical rollup so nothing is left orphaned.
  const orphans = [...validIds].filter((id) => !claimed.has(id));
  if (orphans.length >= 2) {
    const r = await store.rollupTier3Tasks(orphans);
    if (r) emitChat?.({ type: 'task-rollup', parentTaskId: r.id, childTaskIds: r.childIds, userRequest: r.userRequest, summary: r.summary });
    createdCount++;
  }
  log?.(`tier3 cluster: created ${createdCount} rollups covering ${claimed.size + Math.max(0, orphans.length)} tasks`);
  return createdCount;
}

/**
 * Compact when total context exceeds the high threshold. Bring it down to
 * the low threshold in one pass:
 *   1. T1→T2 (mechanical mask) until under LOW or no more candidates
 *   2. T2→T3 (mechanical drop messages) until under LOW or no candidates
 *   3. If still over and tier-3 is at or above its allocation: ONE LLM call
 *      to cluster all tier-3 tasks into tier-4 rollups
 *   4. T4→archive (mechanical flag flip) for oldest if still over
 */
async function maybeCompact({ store, adapter, model, log, emitChat }) {
  const HIGH = TOTAL_BUDGET * HYST_HIGH;
  const LOW  = TOTAL_BUDGET * HYST_LOW;

  let total = await totalContextTokens(store);
  if (total <= HIGH) return;

  log?.(`compact: total=${total} > HIGH=${HIGH}; target LOW=${LOW}`);

  // Step 1: T1 → T2 mask (cheap). Emit task-tier-change so UI can mute results.
  while (total > LOW) {
    const id = await store.findOldestDemotionCandidate(1);
    if (!id) break;
    const before = await loadTaskFull(store, id);
    let removed = 0;
    for (const m of before?.messages ?? []) if (m.kind === 'tool-result') removed += estTokens(m.content);
    await store.demoteToTier2(id);
    emitChat?.({ type: 'task-tier-change', taskId: id, newTier: 2, muted: 'results' });
    total -= removed;
  }
  if (total <= LOW) { log?.(`compact: done after T1→T2 (total=${total})`); return; }

  // Step 2: T2 → T3 drop (cheap). Emit task-tier-change so UI can mute all rows.
  while (total > LOW) {
    const id = await store.findOldestDemotionCandidate(2);
    if (!id) break;
    const before = await loadTaskFull(store, id);
    let removedMsgs = 0;
    for (const m of before?.messages ?? []) removedMsgs += estTokens(m.content);
    const addedSummary = estTokens(before?.summary ?? '');
    await store.demoteToTier3(id, before?.summary || '(no summary)');
    emitChat?.({ type: 'task-tier-change', taskId: id, newTier: 3, muted: 'all' });
    total -= (removedMsgs - addedSummary);
  }
  if (total <= LOW) { log?.(`compact: done after T2→T3 (total=${total})`); return; }

  // Step 3: T3 → T4 via LLM clustering (expensive — only if mechanical didn't suffice)
  const t3 = await tier3TokensFor(store);
  if (t3 >= TIER_3_BUDGET) {
    log?.(`compact: tier3=${t3} >= ${TIER_3_BUDGET}; invoking LLM cluster`);
    await llmClusterTier3({ store, adapter, model, log, emitChat });
    total = await totalContextTokens(store);
    log?.(`compact: after LLM cluster total=${total}`);
  }
  if (total <= LOW) { log?.(`compact: done after T3→T4 (total=${total})`); return; }

  // Step 4: T4 → archive (mechanical). Emit task-archived so UI can mark/hide it.
  while (total > LOW) {
    const tier4 = (await store.listTasks({ tier: 4 }))
      .filter((x) => !x.archived)
      .sort((a, b) => (a.ended ?? a.started ?? 0) - (b.ended ?? b.started ?? 0));
    if (!tier4.length) break;
    const oldest = tier4[0];
    const removed = estTokens(oldest.summary);
    await store.archiveTask(oldest.id);
    emitChat?.({ type: 'task-archived', taskId: oldest.id });
    total -= removed;
  }
  log?.(`compact: done (total=${total}, target=${LOW})`);
}

// ── Stream-aware turn (prose forwarding) ───────────────────────────────────
const HOLDBACK = '<remote-workspace>'.length + 2;

async function runTurnStreaming(adapter, opts, onText) {
  let text = '';
  let sent = 0;
  let inCommands = false;
  const pump = () => {
    if (inCommands) return;
    const idx = text.search(/<remote-workspace/i);
    if (idx === -1) {
      const flushTo = Math.max(sent, text.length - HOLDBACK);
      if (flushTo > sent) { onText?.(text.slice(sent, flushTo)); sent = flushTo; }
    } else {
      if (idx > sent) onText?.(text.slice(sent, idx));
      sent = idx;
      inCommands = true;
    }
  };
  if (typeof adapter.completeStream === 'function') {
    for await (const chunk of adapter.completeStream(opts)) {
      const d = chunk?.choices?.[0]?.delta?.content;
      if (d) { text += d; pump(); }
    }
  } else {
    const res = await adapter.complete(opts);
    text = res?.choices?.[0]?.message?.content ?? '';
    pump();
  }
  if (!inCommands && sent < text.length) { onText?.(text.slice(sent)); }
  return text;
}

// ── Task-op dispatcher ─────────────────────────────────────────────────────
async function dispatchTaskOp(c, store) {
  const a = c.args;
  if (c.verb === 'next-task') {
    // user-request and summary describe the task being CLOSED (the current one),
    // not the new one being opened. See system prompt.
    const t = await store.transitionTo({
      summary: a.summary ?? '',
      userRequest: a['user-request'] ?? '',
    });
    return { ok: true, content: `closed previous task with summary "${a.summary ?? ''}"; opened new task ${t.id}` };
  }
  if (c.verb === 'list-tasks') {
    const list = await store.listTasks({ parentId: a.parent });
    if (!list.length) return { ok: true, content: '(no tasks)' };
    const lines = list.map((t) => {
      const status = t.ended ? 'done' : 'open';
      const tier = `tier${t.tier}`;
      const ur = t.userRequest ? ` ↳ ${t.userRequest.split('\n')[0].slice(0, 100)}` : '';
      const summary = t.summary ? ` — ${t.summary.split('\n')[0].slice(0, 120)}` : '';
      return `${t.id}  [${status}]  [${tier}]${ur}${summary}`;
    });
    return { ok: true, content: lines.join('\n') };
  }
  if (c.verb === 'task-detail') {
    const t = await store.getDetail(a.id);
    if (!t) return { ok: false, content: `task ${a.id} not found` };
    return { ok: true, content: JSON.stringify(t, null, 2) };
  }
  if (c.verb === 'search-tasks') {
    const hits = await store.searchTasks(a.query ?? '');
    if (!hits.length) return { ok: true, content: '(no matches)' };
    const lines = hits.map((t) => {
      const ur = t.userRequest ? ` ↳ ${t.userRequest.split('\n')[0].slice(0, 100)}` : '';
      const sm = (t.summary ?? '').split('\n')[0].slice(0, 140);
      return `${t.id}${ur} — ${sm}`;
    });
    return { ok: true, content: lines.join('\n') };
  }
  return { ok: false, content: `unknown task op: ${c.verb}` };
}

// ── Main agent loop ────────────────────────────────────────────────────────
async function runPromptedAgent({
  adapter,
  messages,           // [{role, content}] from the browser; we only care about the last user message
  model,
  projectDir,         // required: where .agent/tasks/ lives
  maxTurns = DEFAULT_MAX_TURNS,
  // Legacy callbacks (used by /api/chat SSE response):
  onText, onToolCalls, onToolResult, onLog,
  // New chat-event callback (used by /api/message + chat state on server):
  //   onChatEvent({ type, taskId, ...payload })
  // emitted for: 'user-message', 'assistant-text', 'tool-call', 'tool-result',
  //              'diff', 'task-end'.
  onChatEvent,
  // New phase callback:
  //   onPhase('idle' | 'uploading' | 'thinking' | 'downloading')
  onPhase,
  // Abort signal — checked between turns and when waiting on the model.
  signal,
}) {
  if (!projectDir) throw new Error('projectDir required for task-scoped agent');

  const log = (m) => { try { onLog?.(m); } catch {} };
  const emitChat = (ev) => { try { onChatEvent?.(ev); } catch (e) { log(`onChatEvent error: ${e.message}`); } };
  const emitPhase = (p) => { try { onPhase?.(p); } catch {} };
  const checkAbort = () => {
    if (signal?.aborted) {
      const e = new Error('aborted');
      e.name = 'AbortError';
      throw e;
    }
  };

  // Initialize tasks store; this either loads existing state or creates a root task.
  const store = createTasksStore(projectDir);
  await store.init();

  // Extract the user's new message (last user role in incoming).
  const lastUserMsg = [...(messages ?? [])].reverse().find((m) => m.role === 'user');
  const userText = flattenContent(lastUserMsg?.content);
  if (userText) {
    await store.appendMessage({
      kind: 'user-message',
      role: 'user',
      content: userText,
    });
    emitChat({ type: 'user-message', taskId: store.currentId(), content: userText });
  }

  const stats = { turns: 0, toolCalls: 0, toolHistogram: {}, batches: [], loopBreaks: 0, taskOps: 0 };
  let lastKey = '';
  let repeat = 0;

  for (let turn = 1; turn <= maxTurns; turn++) {
    stats.turns = turn;

    // Compute current tier-1 tokens to inject into the system prompt.
    const cur = await store.getCurrent();
    let t1Tokens = 0;
    for (const m of cur?.messages ?? []) t1Tokens += estTokens(m.content);
    const tier1Pct = Math.round((t1Tokens / TIER_1_BUDGET) * 100);

    const sys = buildSystemPrompt({
      taskId: cur?.id ?? '?',
      taskUserRequest: cur?.userRequest ?? '',
      tier1Tokens: t1Tokens,
      tier1Pct,
    });

    // Build the convo from the store. The system reminder is NOT stored —
    // it lives only in the prompt we send each turn. We copy the convo and
    // PREPEND the reminder into the LATEST user message (the one carrying
    // the current question), so the model sees fresh instructions right
    // before the question it's about to answer. The stored convo is untouched.
    //
    // Why latest, not oldest: in a long conversation the oldest user message
    // is far in the past; a reminder there is easy for the model to overlook
    // or treat as ancient context. The latest user message is the freshest
    // and contains what the model is actively responding to.
    //
    // Why prepend (not append) within that latest message: convention —
    // system instructions go before the user's question. Appending after
    // the question can cause the model to respond to the reminder itself
    // instead of the question.
    const fromStore = await buildConvoFromStore(store);
    let latestUserIdx = -1;
    for (let i = fromStore.length - 1; i >= 0; i--) {
      if (fromStore[i].role === 'user') { latestUserIdx = i; break; }
    }
    const convo = fromStore.map((m, i) => {
      if (i !== latestUserIdx) return m;
      return {
        role: 'user',
        content: `<system-reminder>\n${sys}\n</system-reminder>\n\n${m.content}`,
      };
    });
    if (latestUserIdx === -1) {
      // No user messages at all — send the reminder as the only message.
      convo.push({ role: 'user', content: `<system-reminder>\n${sys}\n</system-reminder>` });
    }

    log(`turn ${turn}: ${convo.length} msgs · current=${cur?.id} · t1=${t1Tokens}/${TIER_1_BUDGET}`);

    checkAbort();
    emitPhase('uploading');
    const t0 = Date.now();
    emitPhase('thinking');
    const text = await runTurnStreaming(
      adapter,
      { model, messages: convo, stop: ['</remote-workspace>'] },
      (delta) => { onText?.(delta); emitPhase('downloading'); },
    );
    emitPhase('thinking');
    checkAbort();
    const calls = parseToolCalls(text);
    log(`turn ${turn}: ${text.length} chars in ${Date.now() - t0}ms, ${calls.length} call(s)`);

    if (calls.length === 0) {
      // Final answer reached. Truncate any hallucinated continuation, then
      // store. (Final answers shouldn't contain <remote-workspace> blocks
      // anyway, but the truncate is a no-op in that case.)
      const finalText = truncateAtFirstBlock(text);
      if (finalText.trim()) {
        await store.appendMessage({ kind: 'assistant', role: 'assistant', content: finalText });
        emitChat({ type: 'assistant-text', taskId: cur?.id, content: finalText });
      }
      // Always check budgets before returning — even on the final turn — so
      // long sessions stay within bounds.
      await maybeCompact({ store, adapter, model, log, emitChat });
      log(`done: ${stats.turns} turns, ${stats.toolCalls} tool calls, ${stats.taskOps} task ops`);
      return { content: finalText, stats, terminated: 'stop', store };
    }
    stats.batches.push(calls.length);

    // Store ONLY the first real block. Hallucinated continuation past the
    // close tag is discarded so the model can't "remember" imagined turns
    // on the next loop iteration.
    const assistantText = truncateAtFirstBlock(text);
    await store.appendMessage({ kind: 'assistant', role: 'assistant', content: assistantText });
    // Emit the prose portion (before the <remote-workspace> block) as a chat event.
    const blockIdx = assistantText.search(/<remote-workspace>/i);
    const proseOnly = (blockIdx === -1 ? assistantText : assistantText.slice(0, blockIdx)).trim();
    if (proseOnly) {
      emitChat({ type: 'assistant-text', taskId: cur?.id, content: proseOnly });
    }

    const results = [];
    for (const c of calls) {
      checkAbort();
      if (onToolCalls) onToolCalls([c]);
      // Emit tool-call chat event
      emitChat({
        type: 'tool-call',
        taskId: cur?.id,
        callId: c.id,
        verb: c.verb,
        name: c.name ?? c.verb,
        args: c.args,
      });

      // Loop detection — useful for read tools that the model gets stuck on
      const key = c.verb + '|' + JSON.stringify(c.args);
      if (key === lastKey) repeat++; else { lastKey = key; repeat = 1; }

      let resultContent, resultStatus = 'ok', resultDiff = null;
      if (repeat >= REPEAT_LIMIT) {
        stats.loopBreaks++;
        resultContent = `LOOP DETECTED: this exact request has fired ${repeat} times. Stop requesting and answer with what you have.`;
        resultStatus = 'error';
      } else if (c.kind === 'task-op') {
        stats.taskOps++;
        const r = await dispatchTaskOp(c, store);
        resultContent = r.content;
        resultStatus = r.ok ? 'ok' : 'error';
        log(`  ${c.verb}(${JSON.stringify(c.args)}) -> ${resultStatus}`);
        // If this was a <next-task>, emit a task-end event for the (just-closed) prior task.
        if (c.verb === 'next-task' && r.ok) {
          emitChat({
            type: 'task-end',
            taskId: cur?.id,                      // the task that just closed
            userRequest: c.args['user-request'] ?? '',
            summary: c.args.summary ?? '',
          });
        }
      } else {
        stats.toolCalls++;
        stats.toolHistogram[c.name] = (stats.toolHistogram[c.name] ?? 0) + 1;
        const raw = await execute(c.name, c.args);
        if (typeof raw === 'string' && raw.startsWith('ERROR:')) {
          resultContent = raw;
          resultStatus = 'error';
        } else {
          resultContent = extractContent(raw);
          resultDiff = extractDiff(raw);
        }
        log(`  ${c.name}(${JSON.stringify(c.args)}) -> ${resultStatus === 'error' ? resultContent.slice(0, 80) : resultContent.length + 'b'}`);
      }

      if (onToolResult) {
        onToolResult({
          verb: c.verb, name: c.name ?? c.verb, args: c.args,
          status: resultStatus, content: resultContent,
          diff: resultDiff,
        });
      }
      // Emit tool-result chat event
      emitChat({
        type: 'tool-result',
        taskId: cur?.id,
        callId: c.id,
        verb: c.verb,
        name: c.name ?? c.verb,
        status: resultStatus,
        content: resultContent.slice(0, 8000),
      });
      if (resultDiff) {
        emitChat({
          type: 'diff',
          taskId: cur?.id,
          callId: c.id,
          diff: resultDiff,
        });
      }

      // Persist as task messages.
      await store.appendMessage({
        kind: 'tool-call', role: 'assistant',
        content: `<${c.verb} ...args/>`,    // marker; real content is in assistantText above
        toolName: c.name ?? c.verb, toolArgs: c.args,
      });
      await store.appendMessage({
        kind: 'tool-result', role: 'user',
        content: `<remote-workspace-result op="${c.verb}" status="${resultStatus}">\n${resultContent}\n</remote-workspace-result>`,
        toolName: c.name ?? c.verb, toolStatus: resultStatus,
      });

      results.push({ verb: c.verb, status: resultStatus, content: resultContent });
    }

    // Concat all results into one user message for the next LLM turn (matches
    // what we stored, but the store already has them per-message; the LLM input
    // is rebuilt fresh next turn from the store anyway).

    // Compact if total context is over budget. Cheap mechanical demotions
    // first; LLM clustering only if tier 3 still over after that.
    await maybeCompact({ store, adapter, model, log, emitChat });
  }

  log(`done: max turns (${maxTurns}) reached without converging`);
  return { content: '[MAX TURNS REACHED — agent did not converge]', stats, terminated: 'max-turns', store };
}

// ====== server.mjs ======
/**
 * Local HTTP server for the code_boss web UI. Binds to 127.0.0.1 only.
 *
 * Routes:
 *   GET  /                   serve the HTML page
 *   GET  /api/models         proxy to BASE_URL/models
 *   POST /api/chat           proxy chat completions, streams SSE back to browser
 *   GET  /api/snapshot       session state for the in-page snapshot modal
 *   POST /api/reset          clear the session log
 *   GET  /api/health         ping
 *
 * The server tracks every adapter transaction in `session.events`. The
 * snapshot endpoint returns these for client-side rendering.
 *
 * No npm deps. Node built-in http + the production HTTP adapter.
 */

const RECENT_FILE = path.join(homedir(), '.code-boss', 'recent.json');
const MAX_RECENT = 12;

async function loadRecentProjects() {
  try {
    const text = await readFile(RECENT_FILE, 'utf8');
    const data = JSON.parse(text);
    return Array.isArray(data?.projects) ? data.projects.filter((p) => typeof p === 'string') : [];
  } catch { return []; }
}
async function saveRecentProjects(projects) {
  try {
    await mkdir(path.dirname(RECENT_FILE), { recursive: true });
    await writeFile(RECENT_FILE, JSON.stringify({ projects }, null, 2), 'utf8');
  } catch (e) { console.error('[recent] save failed:', e.message); }
}

/**
 * Walk the assembled diagnostics object and return a list of findings —
 * problems (or confirmations) detected by inspecting the raw data so the
 * user doesn't have to spot them by eye. Each finding has:
 *   - severity: 'ok' | 'info' | 'warn' | 'critical'
 *   - category: 'prompt' | 'fileLog' | 'stderr' | 'gemini' | 'state' | 'config' | 'overall'
 *   - title:    one-line headline
 *   - detail:   longer explanation (optional)
 *
 * Pure function over the diag object — no I/O, no side effects — so it's
 * unit-testable. Add new checks here as we learn new failure modes.
 */
function runDiagnosticChecks(diag) {
  const findings = [];
  const txs = (diag.transactions?.events ?? []).filter((e) => e.type === 'chat_completions');
  const lastChat = txs[txs.length - 1];

  // 1. System reminder injection. After our recent change, the reminder is
  //    prepended INSIDE the latest user message. If it's missing, Gemini
  //    will never see the code_boss instructions and may answer as the
  //    Gemini Enterprise built-in agent. This is the single most useful
  //    check when debugging "the model is ignoring instructions".
  if (lastChat?.request?.messages) {
    const msgs = lastChat.request.messages;
    let lastUserIdx = -1;
    for (let i = msgs.length - 1; i >= 0; i--) {
      if (msgs[i].role === 'user') { lastUserIdx = i; break; }
    }
    if (lastUserIdx >= 0) {
      const content = String(msgs[lastUserIdx].content ?? '');
      const hasReminder = content.includes('<system-reminder>');
      const reminderAtStart = content.trimStart().startsWith('<system-reminder>');
      if (hasReminder && reminderAtStart) {
        findings.push({
          severity: 'ok', category: 'prompt',
          title: 'System reminder is at the start of the latest user message',
          detail: `convo has ${msgs.length} message(s); reminder prepended to msg[${lastUserIdx}] (role=user)`,
        });
      } else if (hasReminder) {
        findings.push({
          severity: 'warn', category: 'prompt',
          title: 'System reminder present but NOT at the start of the latest user message',
          detail: 'Instructions buried mid-message are easier for the model to ignore than ones at the start.',
        });
      } else {
        findings.push({
          severity: 'critical', category: 'prompt',
          title: 'System reminder MISSING from the latest user message',
          detail: `Gemini will not see code_boss instructions. Latest user msg starts: "${content.slice(0, 140)}"`,
        });
      }
    } else {
      findings.push({
        severity: 'warn', category: 'prompt',
        title: 'Last request had no user message',
        detail: `request had ${msgs.length} message(s), none with role=user`,
      });
    }
  } else if (txs.length === 0) {
    findings.push({
      severity: 'info', category: 'state',
      title: 'No chat transactions yet — send a message to enable more checks',
    });
  }

  // 2. File logging actually working? We had a bug where fileLog silently
  //    failed because mkdirSync wasn't in the bundle. Catch a regression
  //    of that class by checking the log file on disk.
  if (diag.project?.logFilePath) {
    if (diag.project.logFileExists === false) {
      findings.push({
        severity: 'critical', category: 'fileLog',
        title: 'Log file does NOT exist on disk',
        detail: `Expected at ${diag.project.logFilePath}. fileLog may be silently failing — check the stderr section for ReferenceError / mkdirSync errors.`,
      });
    } else if (diag.project.logFileBytes === 0 && (diag.server?.uptimeMs ?? 0) > 30_000) {
      findings.push({
        severity: 'warn', category: 'fileLog',
        title: 'Log file exists but is 0 bytes after 30s+ uptime',
        detail: 'No fileLog writes have landed. Either the server is fully idle, or writes are failing somewhere.',
      });
    }
  }

  // 3. Errors / exceptions surfaced in the stderr ring buffer.
  const stderr = diag.stderr ?? [];
  const errorPatterns = [
    /\bReferenceError\b/,
    /\bTypeError\b/,
    /\bSyntaxError\b/,
    /is not defined/,
    /\bENOENT\b/,
    /\bEACCES\b/,
    /\bEADDRINUSE\b/,
    /FAILED TO START/,
    /\bUncaught\b/,
    /\[fileLog\] file write FAILED/,
  ];
  const stderrErrors = stderr.filter((e) => errorPatterns.some((re) => re.test(e.line ?? '')));
  for (const e of stderrErrors.slice(-3)) {
    findings.push({
      severity: 'critical', category: 'stderr',
      title: 'Error captured in stderr buffer',
      detail: (e.line ?? '').slice(0, 300),
    });
  }

  // 4. Gemini identity drift — assistant responding as Gemini Enterprise
  //    built-in instead of code_boss. Strong signal that the system prompt
  //    didn't land or got overridden.
  const identityPatterns = [
    /\bI am Gemini Enterprise\b/i,
    /\bI(?:'| a)m Gemini(?:\b|,|\.)/i,
    /\bMemory Bank agent\b/i,
    /\bI can help you with (?:Jira|Drive|Calendar|Gmail|Confluence)/i,
    /\bGenerate Memories\b/i,
    /\bI am a large language model\b/i,
  ];
  const recentResponses = txs.slice(-5);
  for (const tx of recentResponses) {
    const content = tx?.response?.choices?.[0]?.message?.content ?? '';
    const matched = identityPatterns.find((re) => re.test(content));
    if (matched) {
      findings.push({
        severity: 'warn', category: 'gemini',
        title: 'Assistant replied as a Gemini built-in persona, not as code_boss',
        detail: `Matched "${matched.source}". Response starts: "${content.slice(0, 160)}"`,
      });
      break;
    }
  }

  // 5. finish_reason — length truncation or content filter hits.
  for (const tx of recentResponses) {
    const fr = tx?.response?.choices?.[0]?.finish_reason;
    if (fr === 'length') {
      findings.push({
        severity: 'warn', category: 'gemini',
        title: 'A recent response was cut off (finish_reason=length)',
        detail: 'The model hit max_tokens before finishing. Consider raising the cap.',
      });
      break;
    }
    if (fr === 'content_filter') {
      findings.push({
        severity: 'critical', category: 'gemini',
        title: 'A recent response was blocked (finish_reason=content_filter)',
      });
      break;
    }
  }

  // 6. Stale state hint — many messages on what might be a fresh session.
  if (lastChat?.request?.messages?.length >= 20) {
    findings.push({
      severity: 'info', category: 'state',
      title: `Conversation has ${lastChat.request.messages.length} messages`,
      detail: 'If this is unexpected for the current session, you may have loaded a stale .agent/tasks/state.json from a previous run. Reset to start fresh.',
    });
  }

  // 7. Chat is stuck in 'running' for a long time.
  if (diag.chat?.status === 'running' && (diag.chat.chatStartedAgoMs ?? 0) > 120_000) {
    findings.push({
      severity: 'warn', category: 'state',
      title: `Chat has been 'running' for ${Math.round(diag.chat.chatStartedAgoMs / 1000)}s`,
      detail: 'May be stuck. Consider aborting and retrying.',
    });
  }

  // 8. Basic config sanity.
  if (!diag.project?.activeProject) {
    findings.push({
      severity: 'warn', category: 'config',
      title: 'No active project — chat will fail until one is opened',
    });
  }
  const keyPfx = diag.config?.apiKeyPrefix;
  if (!keyPfx || keyPfx === '(none)' || keyPfx === '') {
    findings.push({
      severity: 'warn', category: 'config',
      title: 'No API key configured',
      detail: 'Edit API_KEY in the bundle CONFIG section.',
    });
  }

  // If nothing notable came up, lead with a positive ok finding so the
  // user can see at a glance "the analyzer ran and found nothing wrong"
  // instead of wondering whether it ran at all.
  if (!findings.some((f) => f.severity === 'critical' || f.severity === 'warn')) {
    findings.unshift({
      severity: 'ok', category: 'overall',
      title: 'No problems detected by automated checks',
    });
  }

  return findings;
}

/** Open a native folder-picker dialog; resolve to the selected absolute path
 *  or null if the user canceled. */
function pickFolderNative() {
  return new Promise((resolve) => {
    let cmd, args, parseStdout = (s) => s.trim() || null;
    if (process.platform === 'win32') {
      cmd = 'powershell';
      args = ['-NoProfile', '-STA', '-Command',
        "Add-Type -AssemblyName System.Windows.Forms | Out-Null; " +
        "$f = New-Object System.Windows.Forms.FolderBrowserDialog; " +
        "$f.Description = 'Choose a project folder'; " +
        "if ($f.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) { Write-Output $f.SelectedPath }"];
    } else if (process.platform === 'darwin') {
      cmd = 'osascript';
      args = ['-e', 'POSIX path of (choose folder with prompt "Choose a project folder")'];
    } else {
      cmd = 'zenity';
      args = ['--file-selection', '--directory', '--title=Choose a project folder'];
    }
    // Do NOT pass windowsHide:true — that suppresses the dialog window too.
    const ps = spawn(cmd, args, { stdio: ['ignore', 'pipe', 'pipe'] });
    let out = '';
    ps.stdout.on('data', (d) => (out += d.toString()));
    ps.on('error', () => resolve(null));
    ps.on('close', () => resolve(parseStdout(out)));
  });
}

const SUMMARIZE = {
  list_models: (d) => `list_models  →  ${d.response?.data?.length ?? '?'} models  (${d.durationMs}ms)`,
  chat_completions: (d) => {
    const fr = d.response?.choices?.[0]?.finish_reason ?? '?';
    const u = d.response?.usage ?? {};
    return `chat_completions  →  finish=${fr}  tokens=${u.total_tokens ?? '?'}  (${d.durationMs}ms)`;
  },
  unlock: (d) => `unlock  →  ${d.url}`,
  'rate-limit': (d) => `rate-limit  →  sleep ${d.ms}ms`,
  usage: (d) => `usage  →  ${JSON.stringify(d)}`,
  error: (d) => `error: ${d.message}`,
};

// Ring buffer that captures everything written to process.stderr so the
// Snapshot UI can show it. Lets the user see what fileLog *would* have
// printed even if the launcher window output got lost/redirected.
const STDERR_BUFFER_MAX = 500;
const stderrBuffer = [];
const _origStderrWrite = process.stderr.write.bind(process.stderr);
process.stderr.write = function (chunk, ...rest) {
  try {
    const s = typeof chunk === 'string' ? chunk : (chunk && chunk.toString) ? chunk.toString() : '';
    if (s) {
      // Split into lines so the buffer entries are line-sized.
      const lines = s.split('\n');
      for (const ln of lines) {
        if (ln === '' && lines.length === 1) continue;
        if (ln === '' && lines.indexOf(ln) === lines.length - 1) continue; // trailing empty after \n
        stderrBuffer.push({ at: new Date().toISOString(), line: ln });
        if (stderrBuffer.length > STDERR_BUFFER_MAX) stderrBuffer.shift();
      }
    }
  } catch {}
  return _origStderrWrite(chunk, ...rest);
};

// BUILD_VERSION is injected by scripts/build.mjs into the bundled HEADER.
// When running src/ directly (dev/tests), it's undefined — fall back to '(dev)'.
const BUILD_VERSION_RUNTIME = (typeof BUILD_VERSION !== 'undefined') ? BUILD_VERSION : '(dev)';

async function startServer({ html, baseURL, apiKey, defaultModel, port = 18888, adapter: providedAdapter, modelsList, initialProject = null }) {
  const session = {
    // Static config
    startedAt: new Date().toISOString(),
    baseURL: baseURL ?? '(dev)',
    defaultModel,
    apiKeyPrefix: (apiKey || '').slice(0, 8) + (apiKey ? '…' : '(empty)'),
    startMs: Date.now(),
    activeProject: null,
    recent: await loadRecentProjects(),

    // Legacy transaction log (kept for /api/snapshot debugging)
    events: [],
    totalTokens: 0,

    // ── Chat state (Phase 1 of server-as-source-of-truth refactor) ──
    // Monotonic counter — every state change bumps it; browsers detect gaps.
    version: 0,
    // chatEvents: the ordered list the UI renders. Each: { id, appendedAtVersion, taskId, type, ...payload }
    chatEvents: [],
    nextEventId: 1,
    // Lifecycle
    status: 'idle',           // 'idle' | 'running' | 'done' | 'error'
    phase: 'idle',            // 'idle' | 'uploading' | 'thinking' | 'downloading'
    error: null,
    // Token counters maintained server-side (browser used to do this)
    chatTokens: { up: 0, down: 0 },
    // Server-enforced timeout for the current chat (settable per /api/extend-timeout)
    chatTimeoutMs: 30 * 60 * 1000,
    chatStartedAt: null,
    // Abort signal for the running agent loop (null when idle)
    abortController: null,
    // SSE subscribers (Phase 2 will populate; Set of res objects)
    streamSubscribers: new Set(),
  };

  // Bumps version, returns the new value. Used by all chat-state setters.
  function bumpVersion() { session.version += 1; return session.version; }

  // Rough token estimate (~4 chars/token) for tracking input/output sizes.
  function estimateTokens(s) { return Math.ceil((s ?? '').length / 4); }

  // ── Chat-state mutators ─────────────────────────────────────────────────
  // Each mutator updates state, bumps version, and (in Phase 2) broadcasts
  // a delta to all SSE subscribers. For now the broadcast is a no-op stub.
  function broadcast(message) {
    // Phase 2 will fill this in. message: { type, version, ...payload }
    for (const res of session.streamSubscribers) {
      try { res.write(`data: ${JSON.stringify(message)}\n\n`); }
      catch { /* dead subscriber; will be cleaned on next iteration */ }
    }
  }
  function setStatus(status) {
    if (session.status === status) return;
    session.status = status;
    broadcast({ type: 'status', version: bumpVersion(), status });
  }
  function setPhase(phase) {
    if (session.phase === phase) return;
    session.phase = phase;
    broadcast({ type: 'phase', version: bumpVersion(), phase });
  }
  function setError(err) {
    session.error = err == null ? null : (err.message || String(err));
    broadcast({ type: 'error', version: bumpVersion(), error: session.error });
  }
  function setTimeout_(ms) {
    session.chatTimeoutMs = Number(ms) || session.chatTimeoutMs;
    broadcast({ type: 'timeout', version: bumpVersion(), timeoutMs: session.chatTimeoutMs });
  }
  function updateTokens(delta) {
    if (delta.up) session.chatTokens.up += delta.up;
    if (delta.down) session.chatTokens.down += delta.down;
    broadcast({ type: 'tokens', version: bumpVersion(), tokens: { ...session.chatTokens } });
  }
  function resetTokens() {
    session.chatTokens = { up: 0, down: 0 };
    broadcast({ type: 'tokens', version: bumpVersion(), tokens: { ...session.chatTokens } });
  }
  // Append a new chat event. Assigns id + appendedAtVersion. Returns the event.
  function appendChatEvent(event) {
    const id = `e${session.nextEventId++}`;
    const ev = { id, appendedAtVersion: session.version + 1, ...event };
    session.chatEvents.push(ev);
    broadcast({ type: 'event', version: bumpVersion(), event: ev });
    return ev;
  }
  // Patch an existing event in place (e.g., to mute tool result on tier 1→2 demotion).
  function patchChatEvent(eventId, patch) {
    const ev = session.chatEvents.find((e) => e.id === eventId);
    if (!ev) return null;
    Object.assign(ev, patch);
    broadcast({ type: 'event-patch', version: bumpVersion(), eventId, patch });
    return ev;
  }
  // Replace entire chat state (used by /api/reset).
  function resetChatState() {
    session.chatEvents = [];
    session.nextEventId = 1;
    session.status = 'idle';
    session.phase = 'idle';
    session.error = null;
    session.chatTokens = { up: 0, down: 0 };
    session.chatStartedAt = null;
    session.abortController = null;
    broadcast({ type: 'reset', version: bumpVersion() });
  }
  // Snapshot of chat state for /api/state.
  function chatStateSnapshot({ eventLimit } = {}) {
    const events = eventLimit && eventLimit < session.chatEvents.length
      ? session.chatEvents.slice(-eventLimit)
      : session.chatEvents;
    return {
      version: session.version,
      status: session.status,
      phase: session.phase,
      tokens: { ...session.chatTokens },
      timeoutMs: session.chatTimeoutMs,
      chatStartedAt: session.chatStartedAt,
      error: session.error,
      activeProject: session.activeProject,
      defaultModel: session.defaultModel,
      recent: session.recent,
      events,
      hasMoreOlder: !!(eventLimit && eventLimit < session.chatEvents.length),
    };
  }
  // Expose helpers so we can use them from /api/chat and from new endpoints later.
  const chatState = {
    bumpVersion, broadcast, setStatus, setPhase, setError, setTimeout: setTimeout_,
    updateTokens, resetTokens, appendChatEvent, patchChatEvent,
    resetChatState, chatStateSnapshot,
  };

  // Append-only project log at <project>/.agent/code-boss.log. Synchronous
  // writes so a hang leaves a complete log up to the last operation.
  //
  // Always mirrors to stderr too — so even if the project dir is unwritable
  // (permissions, disk full, etc.), the user can still see what happened in
  // the PowerShell window where the bundle was launched. Logging silence is
  // the worst kind of bug; this guarantees something is always visible.
  let logDirEnsured = null;
  let loggedFileWriteWarning = false;       // suppress duplicate "file log unavailable" spam
  const logFilePath = () => (session.activeProject ? path.join(session.activeProject, '.agent', 'code-boss.log') : null);
  function fileLog(msg) {
    const line = `${new Date().toISOString()}  ${msg}`;
    // 1) Always print to stderr — guaranteed visible in the launcher window.
    try { process.stderr.write(line + '\n'); } catch {}
    // 2) Append to <project>/.agent/code-boss.log if we can.
    if (!session.activeProject) return;
    try {
      const dir = path.join(session.activeProject, '.agent');
      if (logDirEnsured !== dir) {
        mkdirSync(dir, { recursive: true });
        logDirEnsured = dir;
      }
      appendFileSync(path.join(dir, 'code-boss.log'), line + '\n');
    } catch (e) {
      if (!loggedFileWriteWarning) {
        process.stderr.write(`[fileLog] file write FAILED (will continue with stderr only): ${e.message}\n`);
        process.stderr.write(`[fileLog] attempted path: ${path.join(session.activeProject ?? '?', '.agent', 'code-boss.log')}\n`);
        loggedFileWriteWarning = true;
      }
    }
  }

  async function openProject(p) {
    if (typeof p !== 'string' || !p) throw new Error('invalid project path');
    try {
      const s = await stat(p);
      if (!s.isDirectory()) throw new Error('not a directory');
    } catch (e) { throw new Error('cannot open: ' + e.message); }
    session.activeProject = p;
    session.recent = [p, ...session.recent.filter((x) => x !== p)].slice(0, MAX_RECENT);
    await saveRecentProjects(session.recent);
    logDirEnsured = null;
    logEvent('project-opened', { path: p });
    fileLog(`=== project opened: ${p} ===`);
  }
  function logEvent(type, data) {
    const summary = (SUMMARIZE[type] ?? ((d) => JSON.stringify(d).slice(0, 200)))(data);
    session.events.push({ at: Date.now() - session.startMs, type, summary, ...truncateForSnapshot(data) });
  }
  function truncateForSnapshot(data) {
    // Keep raw request/response for the last transaction view in the modal,
    // but trim huge fields so the snapshot JSON stays manageable.
    if (!data || typeof data !== 'object') return { data };
    const out = { ...data };
    if (out.response && typeof out.response === 'object') {
      const r = out.response;
      const str = JSON.stringify(r);
      if (str.length > 20000) out.response = JSON.parse(str.slice(0, 20000) + '"truncated":true}');
    }
    return out;
  }

  // Use a caller-provided adapter (e.g. the dev claude-code-headless adapter)
  // if given; otherwise default to a fresh production HTTP adapter.
  const adapter = providedAdapter ?? createHttpAdapter({
    baseURL, apiKey,
    onUnlock: (url) => logEvent('unlock', { url }),
    onRateLimit: (ms) => logEvent('rate-limit', { ms }),
    onUsage: (u) => { session.totalTokens += u.total_tokens ?? 0; logEvent('usage', u); },
    onTransaction: (t) => logEvent(t.type, t),
  });

  async function readBody(req) {
    const chunks = [];
    for await (const c of req) chunks.push(c);
    return Buffer.concat(chunks).toString('utf8');
  }
  function sendJson(res, status, body) {
    const s = JSON.stringify(body);
    res.writeHead(status, { 'content-type': 'application/json', 'content-length': Buffer.byteLength(s) });
    res.end(s);
  }
  function sendText(res, status, text, type = 'text/plain') {
    // no-store: the bundled HTML changes on every rebuild; Chrome caches
    // localhost HTML aggressively, which makes "I deployed the new bundle but
    // the page looks the same" the most common false-positive bug report.
    res.writeHead(status, {
      'content-type': type,
      'content-length': Buffer.byteLength(text),
      'cache-control': 'no-store, must-revalidate',
    });
    res.end(text);
  }

  const server = createServer(async (req, res) => {
    try {
      const url = new URL(req.url, `http://${req.headers.host}`);
      const path = url.pathname;

      if (req.method === 'GET' && path === '/') {
        return sendText(res, 200, html, 'text/html; charset=utf-8');
      }
      if (req.method === 'GET' && path === '/api/health') {
        return sendJson(res, 200, { ok: true });
      }
      if (req.method === 'GET' && path === '/api/project-state') {
        // Legacy endpoint kept for the existing browser project picker.
        // New code should use /api/state.
        return sendJson(res, 200, { activeProject: session.activeProject, recent: session.recent });
      }
      if (req.method === 'POST' && path === '/api/pick-folder') {
        const chosen = await pickFolderNative();
        return sendJson(res, 200, { path: chosen });
      }
      if (req.method === 'POST' && path === '/api/open-project') {
        const raw = await readBody(req);
        let body;
        try { body = JSON.parse(raw); }
        catch { return sendJson(res, 400, { error: 'invalid JSON' }); }
        try { await openProject(body.path); }
        catch (e) { return sendJson(res, 400, { error: e.message }); }
        return sendJson(res, 200, { activeProject: session.activeProject, recent: session.recent });
      }
      if (req.method === 'POST' && path === '/api/close-project') {
        session.activeProject = null;
        return sendJson(res, 200, { activeProject: null, recent: session.recent });
      }
      if (req.method === 'GET' && path === '/api/log') {
        if (!session.activeProject) return sendJson(res, 200, { log: '(no project open)', file: null });
        const file = logFilePath();
        try {
          const content = await readFile(file, 'utf8');
          const tail = content.length > 80000 ? content.slice(-80000) : content;
          return sendJson(res, 200, { log: tail, file, bytes: content.length });
        } catch (e) {
          return sendJson(res, 200, { log: `(no log yet — ${e.code || e.message})`, file });
        }
      }
      if (req.method === 'GET' && path === '/api/models') {
        // Dev mode passes a static modelsList; prod uses the adapter.
        if (modelsList) return sendJson(res, 200, { data: modelsList });
        const data = await adapter.listModels();
        return sendJson(res, 200, data);
      }
      if (req.method === 'GET' && path === '/api/snapshot') {
        // Aggregate parallel-tool-batch stats from every agent_run event.
        const agentRuns = session.events.filter((e) => e.type === 'agent_run');
        const allBatches = agentRuns.flatMap((e) => Array.isArray(e.batches) ? e.batches : []);
        const sum = allBatches.reduce((s, n) => s + n, 0);
        const parallelism = {
          runs: agentRuns.length,
          turnsWithTools: allBatches.length,
          totalToolCalls: sum,
          avgPerTurn: allBatches.length ? +(sum / allBatches.length).toFixed(2) : 0,
          maxParallel: allBatches.length ? Math.max(...allBatches) : 0,
          singleCallTurns: allBatches.filter((n) => n === 1).length,
          multiCallTurns: allBatches.filter((n) => n > 1).length,
          batches: allBatches,
        };
        return sendJson(res, 200, {
          startedAt: session.startedAt,
          baseURL: session.baseURL,
          defaultModel: session.defaultModel,
          apiKeyPrefix: session.apiKeyPrefix,
          activeProject: session.activeProject,
          totalTokens: session.totalTokens,
          parallelism,
          events: session.events,
        });
      }
      if (req.method === 'POST' && path === '/api/reset') {
        if (session.status === 'running') {
          return sendJson(res, 409, { error: 'chat is running; cancel first' });
        }
        session.events = [];
        session.totalTokens = 0;
        session.startMs = Date.now();
        chatState.resetChatState();
        return sendJson(res, 200, { ok: true, version: session.version });
      }

      // ── New chat-state endpoints ───────────────────────────────────────
      if (req.method === 'GET' && path === '/api/state') {
        const limit = Number(url.searchParams.get('limit')) || 100;
        return sendJson(res, 200, chatState.chatStateSnapshot({ eventLimit: limit }));
      }
      if (req.method === 'GET' && path === '/api/diagnostics') {
        // One-stop diagnostic dump + investigative findings. Rendered as a
        // full-page view by the Snapshot UI. Findings are surfaced at the top
        // of the view so the user doesn't have to spot problems by eye.
        const lf = logFilePath();
        let logExists = false, logBytes = 0, logTail = '';
        if (lf) {
          try {
            const { statSync, readFileSync } = await import('node:fs');
            const s = statSync(lf);
            logExists = true;
            logBytes = s.size;
            const buf = readFileSync(lf, 'utf8');
            logTail = buf.length > 16000 ? '...' + buf.slice(-16000) : buf;
          } catch (e) { logTail = `(log read failed: ${e.message})`; }
        }
        const memUsage = (() => {
          try { const m = process.memoryUsage(); return { rss: m.rss, heapUsed: m.heapUsed, heapTotal: m.heapTotal }; } catch { return null; }
        })();
        // Reuse the legacy snapshot's parallelism computation.
        const agentRuns = session.events.filter((e) => e.type === 'agent_run');
        const allBatches = agentRuns.flatMap((e) => Array.isArray(e.batches) ? e.batches : []);
        const sum = allBatches.reduce((s, n) => s + n, 0);
        const parallelism = {
          runs: agentRuns.length,
          turnsWithTools: allBatches.length,
          totalToolCalls: sum,
          avgPerTurn: allBatches.length ? +(sum / allBatches.length).toFixed(2) : 0,
          maxParallel: allBatches.length ? Math.max(...allBatches) : 0,
          singleCallTurns: allBatches.filter((n) => n === 1).length,
          multiCallTurns: allBatches.filter((n) => n > 1).length,
          batches: allBatches,
        };
        const diag = {
          build: {
            version: BUILD_VERSION_RUNTIME,
            startedAt: session.startedAt,
          },
          server: {
            uptimeMs: Date.now() - session.startMs,
            pid: process.pid,
            cwd: process.cwd(),
            platform: process.platform,
            nodeVersion: process.version,
            memory: memUsage,
          },
          chat: {
            status: session.status,
            phase: session.phase,
            version: session.version,
            chatStartedAt: session.chatStartedAt,
            chatStartedAgoMs: session.chatStartedAt ? Date.now() - session.chatStartedAt : null,
            timeoutMs: session.chatTimeoutMs,
            error: session.error,
            tokens: { ...session.chatTokens },
            eventCount: session.chatEvents.length,
            abortControllerActive: !!session.abortController,
            streamSubscribers: session.streamSubscribers.size,
          },
          chatEvents: session.chatEvents,
          project: {
            activeProject: session.activeProject,
            logFilePath: lf,
            logFileExists: logExists,
            logFileBytes: logBytes,
            recent: session.recent,
          },
          config: {
            baseURL: session.baseURL,
            defaultModel: session.defaultModel,
            apiKeyPrefix: session.apiKeyPrefix,
            modelInUseDefault: session.defaultModel,
          },
          parallelism,
          transactions: {
            count: session.events.length,
            totalTokens: session.totalTokens,
            events: session.events,
          },
          stderr: stderrBuffer.slice(-200),  // last 200 lines
          logTail,
        };
        diag.findings = runDiagnosticChecks(diag);
        return sendJson(res, 200, diag);
      }
      if (req.method === 'GET' && path === '/api/events') {
        const beforeId = url.searchParams.get('before');
        const limit = Math.min(Number(url.searchParams.get('limit')) || 50, 500);
        let endIdx = session.chatEvents.length;
        if (beforeId) {
          const idx = session.chatEvents.findIndex((e) => e.id === beforeId);
          if (idx > 0) endIdx = idx;
          else if (idx === 0) endIdx = 0;
        }
        const startIdx = Math.max(0, endIdx - limit);
        const slice = session.chatEvents.slice(startIdx, endIdx);
        return sendJson(res, 200, {
          events: slice,
          hasMoreOlder: startIdx > 0,
          version: session.version,
        });
      }
      if (req.method === 'GET' && path === '/api/stream') {
        // SSE subscriber — pushes session state deltas as they happen.
        // Browser opens this once per page load; auto-reconnects on drop.
        res.writeHead(200, {
          'content-type': 'text/event-stream',
          'cache-control': 'no-cache, no-store',
          'connection': 'keep-alive',
        });
        // Send full state once on connect so the browser has a starting point.
        const initial = chatState.chatStateSnapshot({ eventLimit: 100 });
        res.write(`data: ${JSON.stringify({ type: 'init', version: session.version, session: initial })}\n\n`);
        // Subscribe to broadcasts.
        session.streamSubscribers.add(res);
        // Heartbeat every 25s so proxies don't close the connection.
        const heartbeat = setInterval(() => {
          try { res.write(`: heartbeat\n\n`); } catch {}
        }, 25000);
        req.on('close', () => {
          clearInterval(heartbeat);
          session.streamSubscribers.delete(res);
        });
        return;
      }
      if (req.method === 'POST' && path === '/api/message') {
        // Accept user text, kick off agent in background, return immediately.
        const raw = await readBody(req);
        let body; try { body = JSON.parse(raw); } catch { return sendJson(res, 400, { error: 'invalid JSON' }); }
        const text = (body?.text ?? '').toString();
        if (!text.trim()) return sendJson(res, 400, { error: 'text is required' });
        if (!session.activeProject) return sendJson(res, 400, { error: 'no project open' });
        if (session.status === 'running') return sendJson(res, 409, { error: 'chat is already running' });
        fileLog(`/api/message received: model=${body?.model ?? session.defaultModel} text="${text.slice(0, 100).replace(/\s+/g, ' ')}"`);

        // Lock in running state BEFORE we return, so a fast second call sees the lock.
        session.chatStartedAt = Date.now();
        session.abortController = new AbortController();
        chatState.setStatus('running');
        chatState.setPhase('uploading');
        chatState.setError(null);
        chatState.resetTokens();
        chatState.updateTokens({ up: estimateTokens(text) });

        const signal = session.abortController.signal;
        const model = body?.model ?? session.defaultModel;
        const startedAt = Date.now();

        // Server-side timeout: auto-abort if it runs past chatTimeoutMs.
        const timeoutId = setTimeout(() => {
          if (session.abortController) {
            try { session.abortController.abort(); } catch {}
            chatState.setError(`timed out after ${Math.round(session.chatTimeoutMs / 1000)}s`);
          }
        }, session.chatTimeoutMs);

        // Fire-and-forget: run the agent loop async, return 200 now.
        (async () => {
          const prevCwd = process.cwd();
          let cwdChanged = false;
          const chatStart = Date.now();
          try {
            try { process.chdir(session.activeProject); cwdChanged = true; }
            catch (e) { throw new Error('cannot enter project directory: ' + e.message); }
            fileLog(`chat START: model=${model} q="${text.slice(0, 200).replace(/\s+/g, ' ')}"`);
            const result = await runPromptedAgent({
              adapter,
              messages: [{ role: 'user', content: text }],
              model,
              projectDir: session.activeProject,
              maxTurns: 20,
              signal,
              onChatEvent: (ev) => chatState.appendChatEvent(ev),
              onPhase: (p) => chatState.setPhase(p),
              onLog: (msg) => fileLog(msg),
            });
            const dur = Date.now() - chatStart;
            fileLog(`chat DONE: terminated=${result.terminated} turns=${result.stats.turns} calls=${result.stats.toolCalls} duration=${dur}ms`);
            logEvent('agent_run', {
              turns: result.stats.turns,
              toolCalls: result.stats.toolCalls,
              batches: result.stats.batches,
              terminated: result.terminated,
            });
            chatState.setStatus('done');
          } catch (e) {
            const dur = Date.now() - chatStart;
            const aborted = e?.name === 'AbortError' || /aborted/i.test(e?.message ?? '');
            chatState.setError(aborted ? (session.error || 'aborted') : e.message);
            chatState.setStatus('error');
            fileLog(`chat ${aborted ? 'ABORTED' : 'ERROR'} after ${dur}ms: ${e.message}`);
            if (!aborted && e?.stack) {
              fileLog(`stack: ${e.stack.split('\n').slice(0, 4).join(' | ')}`);
            }
            logEvent('error', { message: e.message });
          } finally {
            clearTimeout(timeoutId);
            session.abortController = null;
            session.chatStartedAt = null;
            chatState.setPhase('idle');
            if (cwdChanged) try { process.chdir(prevCwd); } catch {}
          }
        })().catch((e) => {
          // Shouldn't reach here — errors are handled inside. But if it does,
          // make sure we know.
          fileLog(`/api/message background promise leaked an error: ${e?.message ?? e}`);
        });

        return sendJson(res, 200, { ok: true, version: session.version });
      }
      if (req.method === 'POST' && path === '/api/cancel') {
        if (session.abortController) {
          try { session.abortController.abort(); } catch {}
          return sendJson(res, 200, { ok: true, version: session.version });
        }
        return sendJson(res, 200, { ok: true, version: session.version, note: 'no chat in progress' });
      }
      if (req.method === 'POST' && path === '/api/extend-timeout') {
        const raw = await readBody(req);
        let body; try { body = JSON.parse(raw); } catch { return sendJson(res, 400, { error: 'invalid JSON' }); }
        const ms = Number(body?.ms);
        if (!ms || ms < 60000 || ms > 6 * 3600 * 1000) {
          return sendJson(res, 400, { error: 'ms must be 60000..21600000' });
        }
        chatState.setTimeout(ms);
        return sendJson(res, 200, { ok: true, version: session.version, timeoutMs: ms });
      }
      if (req.method === 'POST' && path === '/api/chat') {
        const raw = await readBody(req);
        const body = JSON.parse(raw);
        res.writeHead(200, {
          'content-type': 'text/event-stream',
          'cache-control': 'no-cache',
          'connection': 'keep-alive',
        });

        const send = (chunk) => res.write(`data: ${JSON.stringify(chunk)}\n\n`);
        const emitText = (text) => send({
          id: 'agent', object: 'chat.completion.chunk',
          choices: [{ index: 0, delta: { content: text }, finish_reason: null }],
        });
        // Custom UI events (Claude-Code-style dots / collapsible results).
        const emitEvent = (cb) => send({ _cb: cb });
        const emitFinish = (reason, usage) => send({
          id: 'agent', object: 'chat.completion.chunk',
          choices: [{ index: 0, delta: {}, finish_reason: reason }],
          ...(usage ? { usage } : {}),
        });

        // Point the agent's read tools at the active project. Single-user
        // local app — process.chdir for the duration of the request is OK.
        const prevCwd = process.cwd();
        let cwdChanged = false;
        if (session.activeProject) {
          try { process.chdir(session.activeProject); cwdChanged = true; }
          catch (e) {
            emitText(`(error: cannot enter project directory: ${e.message})`);
            emitFinish('stop');
            res.write('data: [DONE]\n\n');
            return res.end();
          }
        } else {
          emitText('(no project open — pick one from the picker first)\n');
          emitFinish('stop');
          res.write('data: [DONE]\n\n');
          return res.end();
        }

        const lastUser = [...(body.messages ?? [])].reverse().find((m) => m.role === 'user');
        fileLog(`chat: model=${body.model} q="${String(lastUser?.content ?? '').slice(0, 200).replace(/\s+/g, ' ')}"`);
        try {
          let emittedAnything = false;
          const result = await runPromptedAgent({
            adapter,
            messages: body.messages,
            model: body.model,
            projectDir: session.activeProject,
            maxTurns: 20,
            onText: (delta) => {
              if (delta) { emittedAnything = true; emitText(delta); }
            },
            onToolCalls: (calls) => {
              for (const c of calls) {
                emittedAnything = true;
                // For task ops, send a more readable label.
                const label = c.verb;
                const argStr = Object.entries(c.args)
                  .filter(([k]) => k !== 'content')  // skip body for write
                  .map(([k, v]) => `${k}=${String(v).slice(0, 60)}`)
                  .join(', ');
                emitEvent({ t: 'tool', name: c.name ?? label, verb: label, args: argStr });
              }
            },
            onToolResult: ({ name, verb, status, content, diff }) => {
              const nonEmptyLines = content.split('\n').filter((l) => l.trim()).length;
              const v = verb ?? name;
              let summary;
              if (status === 'error') summary = content.split('\n')[0].slice(0, 140);
              else if (name === 'list_dir' || v === 'list') summary = `${nonEmptyLines} entries`;
              else if (name === 'read_file' || v === 'read') summary = `Read ${content.split('\n').length} lines`;
              else if (name === 'grep' || v === 'search') summary = content.startsWith('(no matches') ? 'No matches' : `${nonEmptyLines} matching lines`;
              else if (name === 'glob' || v === 'find') summary = content.startsWith('(no matches') ? 'No files' : `${nonEmptyLines} files`;
              else if (name === 'write_file' || v === 'write') summary = content.replace(/^wrote\s+/, '');
              else if (name === 'edit_file' || v === 'edit') summary = content.replace(/^edited\s+/, '');
              else if (name === 'powershell' || v === 'powershell') {
                const m = content.match(/^exit (\S+)\s+in\s+(\d+ms)/);
                summary = m ? `exit ${m[1]} in ${m[2]}` : `${content.length} bytes`;
              }
              else if (v === 'next-task') summary = content.replace(/^closed previous task.*?opened new task /, '→ ');
              else if (v === 'list-tasks') summary = `${nonEmptyLines} tasks`;
              else if (v === 'task-detail') summary = 'task detail';
              else if (v === 'search-tasks') summary = `${nonEmptyLines} matches`;
              else summary = `${content.length} bytes`;
              emitEvent({ t: 'result', status, summary, full: content.slice(0, 8000) });
              if (diff) {
                emitEvent({ t: 'diff', diff, summary });
              }
            },
            onLog: (msg) => fileLog(msg),
          });
          fileLog(`chat done: terminated=${result.terminated} turns=${result.stats.turns} calls=${result.stats.toolCalls} batches=[${result.stats.batches.join(',')}]`);
          // Detect the "model returned nothing useful" case.
          if (!emittedAnything && (!result.content || result.content.trim().length === 0)) {
            emitText('\n⚠️ Model returned an empty response (terminated=' +
              (result.terminated ?? 'unknown') +
              '). Open the Snapshot to see the raw response.\n');
          }
          emitFinish('stop', { total_tokens: result.stats.toolCalls });
          logEvent('agent_run', {
            turns: result.stats.turns,
            toolCalls: result.stats.toolCalls,
            batches: result.stats.batches,
            terminated: result.terminated,
          });
        } catch (e) {
          logEvent('error', { message: e.message });
          fileLog(`chat ERROR: ${e.message}`);
          send({ error: { message: e.message, stack: e.stack } });
        } finally {
          if (cwdChanged) process.chdir(prevCwd);
          res.write('data: [DONE]\n\n');
          res.end();
        }
        return;
      }
      sendText(res, 404, 'Not found');
    } catch (e) {
      logEvent('error', { message: e.message });
      const body = JSON.stringify({ error: { message: e.message, stack: e.stack } });
      res.writeHead(500, { 'content-type': 'application/json' });
      res.end(body);
    }
  });

  if (initialProject) {
    try { await openProject(initialProject); }
    catch (e) { console.error('[server] could not open initial project:', e.message); }
  }

  return new Promise((resolve, reject) => {
    server.once('error', reject);
    server.listen(port, '127.0.0.1', () => resolve({ server, session, port }));
  });
}

// ====== cli-picker.mjs ======
/**
 * Interactive CLI prompt: choose a project to open before the web UI starts.
 *
 * Menu shape:
 *   [1] <current working directory>   (★ initialized | new project)
 *   [2] Open a different folder...    (spawns native dialog)
 *   Recent:
 *   [3..6] up to four recent projects (★ initialized | new project)
 *
 * Returns the absolute path of the chosen folder. Falls back to cwd in a
 * non-TTY environment.
 */

const C = process.stdout.isTTY
  ? { reset:'\x1b[0m', bold:'\x1b[1m', dim:'\x1b[2m', green:'\x1b[32m', cyan:'\x1b[36m', yellow:'\x1b[33m' }
  : new Proxy({}, { get: () => '' });

async function isInitialized(dir) {
  try {
    return (await stat(path.join(dir, '.agent'))).isDirectory();
  } catch { return false; }
}

function prompt(question) {
  const rl = createInterface({ input: process.stdin, output: process.stdout });
  return new Promise((r) => rl.question(question, (a) => { rl.close(); r(a); }));
}

function markerFor(init) {
  return init
    ? `${C.green}★ initialized${C.reset}`
    : `${C.dim}new project${C.reset}`;
}

async function selectProject({ recent = [], cwd = process.cwd() } = {}) {
  // Non-interactive fallback: just use cwd.
  if (!process.stdin.isTTY) {
    console.error(`[cli-picker] non-TTY, defaulting to cwd: ${cwd}`);
    return cwd;
  }

  const cwdInit = await isInitialized(cwd);
  const recentFiltered = recent.filter((p) => p !== cwd).slice(0, 4);
  const recentInfo = await Promise.all(
    recentFiltered.map(async (p) => ({ path: p, init: await isInitialized(p) })),
  );

  console.log('');
  console.log(`  ${C.bold}code_boss${C.reset}`);
  console.log(`  ${C.dim}─────────${C.reset}`);
  console.log('');
  console.log('  Open a project:');
  console.log('');

  const choices = [];
  console.log(`  ${C.cyan}[1]${C.reset} ${cwd}    ${markerFor(cwdInit)}`);
  choices.push({ kind: 'path', value: cwd });

  console.log(`  ${C.cyan}[2]${C.reset} ${C.dim}Open a different folder…${C.reset}`);
  choices.push({ kind: 'pick' });

  if (recentInfo.length > 0) {
    console.log('');
    console.log(`  ${C.dim}Recent:${C.reset}`);
    for (let i = 0; i < recentInfo.length; i++) {
      const idx = i + 3;
      const r = recentInfo[i];
      console.log(`  ${C.cyan}[${idx}]${C.reset} ${r.path}    ${markerFor(r.init)}`);
      choices.push({ kind: 'path', value: r.path });
    }
  }

  console.log('');
  const raw = (await prompt(`  Enter choice [1]: `)).trim();
  const idx = raw === '' ? 0 : parseInt(raw, 10) - 1;

  if (Number.isNaN(idx) || idx < 0 || idx >= choices.length) {
    console.log(`  ${C.yellow}Invalid choice. Exiting.${C.reset}`);
    process.exit(1);
  }

  const chosen = choices[idx];
  if (chosen.kind === 'pick') {
    console.log(`  ${C.dim}Opening folder dialog…${C.reset}`);
    const picked = await pickFolderNative();
    if (!picked) {
      console.log(`  ${C.yellow}No folder selected. Exiting.${C.reset}`);
      process.exit(0);
    }
    return picked;
  }
  return chosen.value;
}



